{
  "name": "EduAnalytica - Evaluador Académico",
  "description": "Una herramienta avanzada para analizar el rendimiento académico procesando archivos de Excel de estudiantes y claves de respuestas, con visualizaciones detalladas por materia (Lenguaje y Matemáticas)."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("No se pudo encontrar el elemento root para montar la aplicación");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum Subject {
  LENGUAJE = 'Lenguaje',
  MATEMATICAS = 'Matemáticas'
}

export interface AnswerKey {
  pregunta: string;
  respuestaCorrecta: string;
  materia: Subject;
}

export interface StudentRecord {
  nombre: string;
  respuestas: Record<string, string>;
}

export interface QuestionStats {
  pregunta: string;
  materia: Subject;
  aciertos: number;
  total: number;
  porcentaje: number;
}

export interface ProcessedResults {
  stats: QuestionStats[];
  totalStudents: number;
  avgLenguaje: number;
  avgMatematicas: number;
}

import * as XLSX from 'xlsx';
import { AnswerKey, StudentRecord, Subject, ProcessedResults, QuestionStats } from '../types';

export const parseExcelFile = async (file: File): Promise<any[]> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = new Uint8Array(e.target?.result as ArrayBuffer);
        const workbook = XLSX.read(data, { type: 'array' });
        const firstSheetName = workbook.SheetNames[0];
        const worksheet = workbook.Sheets[firstSheetName];
        const jsonData = XLSX.utils.sheet_to_json(worksheet);
        resolve(jsonData);
      } catch (err) {
        reject(err);
      }
    };
    reader.onerror = (err) => reject(err);
    reader.readAsArrayBuffer(file);
  });
};

export const processAcademicData = (
  estudiantesData: any[],
  respuestasData: any[]
): ProcessedResults => {
  // 1. Transformar clave de respuestas
  // Se espera que respuestasData tenga: "Pregunta", "Respuesta Correcta", "Materia"
  const keys: AnswerKey[] = respuestasData.map(row => ({
    pregunta: String(row['Pregunta'] || row['pregunta'] || '').trim(),
    respuestaCorrecta: String(row['Respuesta Correcta'] || row['respuesta_correcta'] || row['Respuesta'] || '').trim(),
    materia: (String(row['Materia'] || row['materia'] || '').toLowerCase().includes('mat') 
      ? Subject.MATEMATICAS 
      : Subject.LENGUAJE)
  })).filter(k => k.pregunta !== '');

  // 2. Transformar datos de estudiantes
  // Se espera que la primera columna sea el nombre y las demás sean IDs de preguntas que coincidan con la clave
  const students: StudentRecord[] = estudiantesData.map(row => {
    const { Nombre, nombre, ...resps } = row;
    return {
      nombre: Nombre || nombre || 'Estudiante Anónimo',
      respuestas: resps
    };
  });

  const totalStudents = students.length;
  const stats: QuestionStats[] = keys.map(key => {
    let aciertos = 0;
    students.forEach(student => {
      const studentAnswer = String(student.respuestas[key.pregunta] || '').trim();
      if (studentAnswer.toLowerCase() === key.respuestaCorrecta.toLowerCase()) {
        aciertos++;
      }
    });

    return {
      pregunta: key.pregunta,
      materia: key.materia,
      aciertos,
      total: totalStudents,
      porcentaje: totalStudents > 0 ? (aciertos / totalStudents) * 100 : 0
    };
  });

  const lenguajeStats = stats.filter(s => s.materia === Subject.LENGUAJE);
  const matematicasStats = stats.filter(s => s.materia === Subject.MATEMATICAS);

  const avgLenguaje = lenguajeStats.length > 0 
    ? lenguajeStats.reduce((acc, curr) => acc + curr.porcentaje, 0) / lenguajeStats.length 
    : 0;

  const avgMatematicas = matematicasStats.length > 0 
    ? matematicasStats.reduce((acc, curr) => acc + curr.porcentaje, 0) / matematicasStats.length 
    : 0;

  return {
    stats,
    totalStudents,
    avgLenguaje,
    avgMatematicas
  };
};

import React, { useRef } from 'react';

interface FileUploadProps {
  label: string;
  description: string;
  accept: string;
  onFileSelect: (file: File | null) => void;
  selectedFileName?: string;
}

const FileUpload: React.FC<FileUploadProps> = ({ 
  label, 
  description, 
  accept, 
  onFileSelect,
  selectedFileName 
}) => {
  const inputRef = useRef<HTMLInputElement>(null);

  const handleContainerClick = () => {
    inputRef.current?.click();
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0] || null;
    onFileSelect(file);
  };

  return (
    <div 
      onClick={handleContainerClick}
      className={`relative border-2 border-dashed rounded-xl p-6 transition-all cursor-pointer group
        ${selectedFileName ? 'border-indigo-500 bg-indigo-50' : 'border-slate-300 hover:border-indigo-400 hover:bg-slate-50'}`}
    >
      <input 
        type="file" 
        ref={inputRef}
        onChange={handleFileChange}
        accept={accept}
        className="hidden"
      />
      <div className="flex flex-col items-center text-center space-y-2">
        <div className={`p-3 rounded-full transition-colors 
          ${selectedFileName ? 'bg-indigo-100 text-indigo-600' : 'bg-slate-100 text-slate-500 group-hover:bg-indigo-100 group-hover:text-indigo-600'}`}>
          <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
          </svg>
        </div>
        <div className="flex flex-col">
          <span className="font-semibold text-slate-700">{label}</span>
          <span className="text-sm text-slate-500">{description}</span>
        </div>
        {selectedFileName && (
          <div className="mt-2 inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-indigo-100 text-indigo-800 border border-indigo-200">
            {selectedFileName}
          </div>
        )}
      </div>
    </div>
  );
};

export default FileUpload;

import React from 'react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  Cell,
  Legend
} from 'recharts';
import { ProcessedResults, Subject } from '../types';

interface DashboardProps {
  results: ProcessedResults;
}

const Dashboard: React.FC<DashboardProps> = ({ results }) => {
  const lenguajeData = results.stats.filter(s => s.materia === Subject.LENGUAJE);
  const matematicasData = results.stats.filter(s => s.materia === Subject.MATEMATICAS);

  const CustomTooltip = ({ active, payload, label }: any) => {
    if (active && payload && payload.length) {
      return (
        <div className="bg-white p-4 border rounded-lg shadow-lg">
          <p className="font-bold text-slate-800">{`Pregunta: ${label}`}</p>
          <p className="text-indigo-600 font-medium">
            {`Éxito: ${payload[0].value.toFixed(1)}%`}
          </p>
          <p className="text-slate-500 text-sm">
            {`${payload[0].payload.aciertos} de ${payload[0].payload.total} estudiantes`}
          </p>
        </div>
      );
    }
    return null;
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-700">
      {/* Summary Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex flex-col items-center justify-center">
          <span className="text-slate-500 text-sm font-medium uppercase tracking-wider">Total Estudiantes</span>
