          <span className="text-slate-500 text-sm font-medium uppercase tracking-wider">Promedio Lenguaje</span>
          <span className="text-4xl font-bold text-emerald-600 mt-1">{results.avgLenguaje.toFixed(1)}%</span>
        </div>
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex flex-col items-center justify-center">
          <span className="text-slate-500 text-sm font-medium uppercase tracking-wider">Promedio Matemáticas</span>
          <span className="text-4xl font-bold text-blue-600 mt-1">{results.avgMatematicas.toFixed(1)}%</span>
        </div>
      </div>

      {/* Charts Section */}
      <div className="grid grid-cols-1 gap-8">
        {/* Lenguaje Chart */}
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <div className="flex items-center space-x-2 mb-6">
            <div className="w-2 h-8 bg-emerald-500 rounded-full"></div>
            <h3 className="text-xl font-bold text-slate-800">Resultados Lenguaje</h3>
