                  dataKey="pregunta" 
                  angle={-45} 
                  textAnchor="end" 
                  interval={0} 
                  height={60}
                  tick={{ fontSize: 12, fill: '#64748b' }}
                />
                <YAxis unit="%" domain={[0, 100]} tick={{ fontSize: 12, fill: '#64748b' }} />
                <Tooltip content={<CustomTooltip />} />
                <Bar dataKey="porcentaje" name="Porcentaje de Acierto">
                  {lenguajeData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.porcentaje > 70 ? '#10b981' : entry.porcentaje > 40 ? '#f59e0b' : '#ef4444'} />
                  ))}
                </Bar>
