        {/* Matemáticas Chart */}
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <div className="flex items-center space-x-2 mb-6">
            <div className="w-2 h-8 bg-blue-500 rounded-full"></div>
            <h3 className="text-xl font-bold text-slate-800">Resultados Matemáticas</h3>
          </div>
          <div className="h-[400px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={matematicasData} margin={{ top: 20, right: 30, left: 20, bottom: 60 }}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis 
                  dataKey="pregunta" 
                  angle={-45} 
                  textAnchor="end" 
                  interval={0} 
                  height={60}
                  tick={{ fontSize: 12, fill: '#64748b' }}
                />
                <YAxis unit="%" domain={[0, 100]} tick={{ fontSize: 12, fill: '#64748b' }} />
                <Tooltip content={<CustomTooltip />} />
                <Bar dataKey="porcentaje" name="Porcentaje de Acierto">
