        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-slate-50">
              <tr>
                <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase">Pregunta</th>
                <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase">Materia</th>
                <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase">Aciertos</th>
                <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase">Porcentaje</th>
