                  <td className="px-6 py-4 text-slate-600">{stat.aciertos} / {stat.total}</td>
                  <td className="px-6 py-4 font-bold text-slate-800">{stat.porcentaje.toFixed(1)}%</td>
                  <td className="px-6 py-4">
                    <div className="w-full bg-slate-200 rounded-full h-2 max-w-[100px]">
