export default Dashboard;

import React, { useState, useCallback } from 'react';
import FileUpload from './components/FileUpload';
import Dashboard from './components/Dashboard';
import { parseExcelFile, processAcademicData } from './utils/excelParser';
import { ProcessedResults } from './types';

const App: React.FC = () => {
  const [estudiantesFile, setEstudiantesFile] = useState<File | null>(null);
  const [respuestasFile, setRespuestasFile] = useState<File | null>(null);
  const [loading, setLoading] = useState(false);
  const [results, setResults] = useState<ProcessedResults | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleProcess = useCallback(async () => {
    if (!estudiantesFile || !respuestasFile) {
      setError("Por favor, sube ambos archivos para continuar.");
      return;
    }

    setLoading(true);
    setError(null);

    try {
      const [estudiantesData, respuestasData] = await Promise.all([
        parseExcelFile(estudiantesFile),
        parseExcelFile(respuestasFile)
      ]);

      const processed = processAcademicData(estudiantesData, respuestasData);
      setResults(processed);
    } catch (err) {
      console.error(err);
      setError("Error al procesar los archivos. Asegúrate de que son archivos Excel válidos y siguen el formato esperado.");
    } finally {
      setLoading(false);
    }
  }, [estudiantesFile, respuestasFile]);

  const reset = () => {
    setEstudiantesFile(null);
    setRespuestasFile(null);
    setResults(null);
    setError(null);
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-10">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4 flex items-center justify-between">
          <div className="flex items-center space-x-3">
            <div className="bg-indigo-600 p-2 rounded-lg">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" />
              </svg>
            </div>
            <h1 className="text-2xl font-bold text-slate-900 tracking-tight">EduAnalytica</h1>
          </div>
          {results && (
            <button 
              onClick={reset}
              className="text-sm font-medium text-indigo-600 hover:text-indigo-800 transition-colors flex items-center space-x-1"
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
              </svg>
              <span>Nueva Evaluación</span>
            </button>
          )}
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-grow max-w-7xl mx-auto w-full px-4 sm:px-6 lg:px-8 py-8">
        {!results ? (
          <div className="max-w-2xl mx-auto space-y-8 mt-12">
            <div className="text-center space-y-3">
              <h2 className="text-3xl font-extrabold text-slate-900 sm:text-4xl">
                Análisis de Resultados Académicos
              </h2>
              <p className="text-lg text-slate-600 max-w-md mx-auto">
                Carga tus archivos de Excel para generar automáticamente estadísticas de rendimiento en Lenguaje y Matemáticas.
              </p>
            </div>

            <div className="bg-white p-8 rounded-3xl shadow-xl shadow-slate-200/50 border border-slate-100 space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <FileUpload 
                  label="Archivo Estudiantes" 
                  description="Listado de alumnos y sus respuestas"
                  accept=".xlsx, .xls, .csv"
                  onFileSelect={setEstudiantesFile}
                  selectedFileName={estudiantesFile?.name}
                />
                <FileUpload 
                  label="Clave de Respuestas" 
                  description="Respuestas correctas y materias"
                  accept=".xlsx, .xls, .csv"
                  onFileSelect={setRespuestasFile}
                  selectedFileName={respuestasFile?.name}
                />
              </div>

              {error && (
                <div className="bg-red-50 border-l-4 border-red-500 p-4 rounded-lg">
                  <div className="flex">
                    <div className="flex-shrink-0">
                      <svg className="h-5 w-5 text-red-400" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor">
                        <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8.707 7.293a1 1 0 00-1.414 1.414L8.586 10l-1.293 1.293a1 1 0 101.414 1.414L10 11.414l1.293 1.293a1 1 0 001.414-1.414L11.414 10l1.293-1.293a1 1 0 00-1.414-1.414L10 8.586 8.707 7.293z" clipRule="evenodd" />
                      </svg>
                    </div>
                    <div className="ml-3">
                      <p className="text-sm text-red-700">{error}</p>
                    </div>
                  </div>
                </div>
              )}

              <button
                onClick={handleProcess}
                disabled={loading || !estudiantesFile || !respuestasFile}
                className={`w-full py-4 px-6 rounded-xl font-bold text-white shadow-lg transition-all transform hover:-translate-y-0.5 active:translate-y-0
                  ${loading || !estudiantesFile || !respuestasFile 
                    ? 'bg-slate-300 cursor-not-allowed shadow-none' 
                    : 'bg-indigo-600 hover:bg-indigo-700 hover:shadow-indigo-200'}`}
              >
                {loading ? (
                  <span className="flex items-center justify-center">
                    <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-white" xmlns="http://www.w3.org/2000/center" fill="none" viewBox="0 0 24 24">
                      <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                      <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                    </svg>
                    Procesando datos...
                  </span>
                ) : 'Generar Resultados'}
              </button>

              <div className="pt-4 text-center">
                <p className="text-xs text-slate-400">
                  Formato esperado: El archivo de respuestas debe tener columnas "Pregunta", "Respuesta Correcta" y "Materia".
                </p>
              </div>
            </div>
          </div>
        ) : (
          <Dashboard results={results} />
        )}
      </main>

      {/* Footer */}
      <footer className="bg-white border-t border-slate-200 py-6 mt-12">
        <div className="max-w-7xl mx-auto px-4 text-center text-slate-500 text-sm">
          EduAnalytica &copy; {new Date().getFullYear()} - Sistema Inteligente de Gestión Escolar
        </div>
      </footer>
    </div>
  );
};

export default App;

import * as XLSX from 'xlsx';
import { AnswerKey, StudentRecord, Subject, ProcessedResults, QuestionStats } from '../types';

export const parseExcelFile = async (file: File): Promise<any[]> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = new Uint8Array(e.target?.result as ArrayBuffer);
        const workbook = XLSX.read(data, { type: 'array' });
        const firstSheetName = workbook.SheetNames[0];
        const worksheet = workbook.Sheets[firstSheetName];
        const jsonData = XLSX.utils.sheet_to_json(worksheet);
        resolve(jsonData);
      } catch (err) {
        reject(err);
      }
    };
    reader.onerror = (err) => reject(err);
    reader.readAsArrayBuffer(file);
  });
};

export const processAcademicData = (
  estudiantesData: any[],
  respuestasData: any[]
): ProcessedResults => {
  // 1. Transformar clave de respuestas
  // Se adapta para buscar específicamente 'respuesta corecta' como solicitó el usuario
  const keys: AnswerKey[] = respuestasData.map(row => {
    const findValue = (possibleKeys: string[]) => {
      const foundKey = Object.keys(row).find(k => 
        possibleKeys.some(pk => k.toLowerCase().trim() === pk.toLowerCase().trim())
      );
      return foundKey ? String(row[foundKey]).trim() : '';
    };

    return {
      pregunta: findValue(['Pregunta', 'Item', 'ID']),
      respuestaCorrecta: findValue(['respuesta corecta', 'respuesta correcta', 'Respuesta Correcta', 'Respuesta']),
      materia: (findValue(['Materia']).toLowerCase().includes('mat') 
        ? Subject.MATEMATICAS 
        : Subject.LENGUAJE)
    };
  }).filter(k => k.pregunta !== '');

  // 2. Transformar datos de estudiantes
  const students: StudentRecord[] = estudiantesData.map(row => {
    // Buscamos la columna del nombre de forma flexible
    const nombreKey = Object.keys(row).find(k => k.toLowerCase().includes('nombre')) || '';
    const { [nombreKey]: studentName, ...resps } = row;

    return {
      nombre: String(studentName || 'Estudiante Anónimo'),
      respuestas: resps as Record<string, string>
    };
  });

  const totalStudents = students.length;
  const stats: QuestionStats[] = keys.map(key => {
