import * as XLSX from 'xlsx';
import { AnswerKey, Subject, ProcessedResults, QuestionStats } from '../types';

/**
 * Normaliza un string para comparaciones: quita espacios y lo pasa a minúsculas.
 */
const normalize = (val: any): string => {
  if (val === null || val === undefined) return '';
  return String(val).trim().toLowerCase();
};

export const parseExcelFile = async (file: File): Promise<any[]> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = new Uint8Array(e.target?.result as ArrayBuffer);
        const workbook = XLSX.read(data, { type: 'array' });
        const firstSheetName = workbook.SheetNames[0];
        const worksheet = workbook.Sheets[firstSheetName];

        // Obtenemos los datos brutos
        const jsonData = XLSX.utils.sheet_to_json(worksheet, { defval: "" });

        // Normalizamos las llaves (nombres de columnas) de cada objeto para evitar errores de espacios
        const normalizedData = jsonData.map((row: any) => {
          const newRow: any = {};
          Object.keys(row).forEach(key => {
            newRow[normalize(key)] = row[key];
          });
          return newRow;
        });

        resolve(normalizedData);
      } catch (err) {
        reject(err);
      }
    };
    reader.onerror = (err) => reject(err);
    reader.readAsArrayBuffer(file);
  });
};

export const processAcademicData = (
  estudiantesData: any[],
  respuestasData: any[]
): ProcessedResults => {
  // 1. Mapear las respuestas correctas desde el archivo de respuestas
  // Buscamos las columnas clave en el archivo de respuestas (normalizadas)
  const keys: AnswerKey[] = respuestasData.map(row => {
    const findValueByNormalizedKey = (possibleNames: string[]) => {
      const normalizedNames = possibleNames.map(n => normalize(n));
      const foundKey = Object.keys(row).find(k => normalizedNames.includes(normalize(k)));
      return foundKey ? String(row[foundKey]).trim() : '';
    };

    const preguntaId = findValueByNormalizedKey(['PREGUNTA ID', 'ID', 'Pregunta ID', 'CODIGO', 'NUMERO']);
    const respuestaCorrecta = findValueByNormalizedKey(['respuesta corecta', 'respuesta correcta', 'Correcta', 'CLAVE', 'RESPUESTA']);
    const materiaStr = findValueByNormalizedKey(['Materia', 'Asignatura', 'Area', 'Componente']).toLowerCase();

    const materia = materiaStr.includes('mat') 
