      : Subject.LENGUAJE;

    return {
      pregunta: preguntaId,
      respuestaCorrecta: respuestaCorrecta,
      materia: materia
    };
  }).filter(k => k.pregunta !== '');

  const totalStudents = estudiantesData.length;

  // 2. Procesamiento de Aciertos Columna por Columna
  const stats: QuestionStats[] = keys.map(key => {
    let aciertos = 0;
    const targetColumn = normalize(key.pregunta); // El ID de la pregunta es nuestra columna objetivo
    const expectedValue = normalize(key.respuestaCorrecta);

    estudiantesData.forEach(studentRow => {
      // Buscamos en la fila del estudiante la columna que normalizada coincida con nuestro targetColumn
      const studentValue = normalize(studentRow[targetColumn]);

      if (studentValue === expectedValue && expectedValue !== '') {
        aciertos++;
      }
    });

    const porcentaje = totalStudents > 0 ? (aciertos / totalStudents) * 100 : 0;

    return {
      pregunta: key.pregunta,
      materia: key.materia,
      aciertos: aciertos, // Este es el conteo solicitado
      total: totalStudents,
      porcentaje: porcentaje,
      respuestaCorrecta: key.respuestaCorrecta
    };
  });

  // 3. Promedios finales
  const lenguajeStats = stats.filter(s => s.materia === Subject.LENGUAJE);
  const matematicasStats = stats.filter(s => s.materia === Subject.MATEMATICAS);

  const avgLenguaje = lenguajeStats.length > 0 
    ? lenguajeStats.reduce((acc, curr) => acc + curr.porcentaje, 0) / lenguajeStats.length 
    : 0;

  const avgMatematicas = matematicasStats.length > 0 
    ? matematicasStats.reduce((acc, curr) => acc + curr.porcentaje, 0) / matematicasStats.length 
    : 0;

  return {
    stats,
    totalStudents,
    avgLenguaje,
    avgMatematicas
  };
};

