  const keys: AnswerKey[] = respuestasData.map(row => {
    const findValue = (possibleKeys: string[]) => {
      const foundKey = Object.keys(row).find(k => 
        possibleKeys.some(pk => k.toLowerCase().trim() === pk.toLowerCase().trim())
      );
      return foundKey ? String(row[foundKey]).trim() : '';
    };

    // Siguiendo el orden del usuario: "Pregunta id" y "Respuesta Correcta"
    const preguntaId = findValue(['Pregunta id', 'ID', 'CODIGO', 'PREGUNTA']);
    const respuestaCorrecta = findValue(['Respuesta Correcta', 'RESPUESTA', 'CLAVE', 'CORRECTA']);
    const materiaStr = findValue(['Área', 'Materia', 'Area', 'Asignatura']).toLowerCase();

    const materia = materiaStr.includes('mat') 
