      : Subject.LENGUAJE;

    return {
      pregunta: preguntaId,
      respuestaCorrecta: clean(respuestaCorrecta),
      materia: materia
    };
  }).filter(k => k.pregunta !== '');

  const totalStudents = estudiantesData.length;

  // 2. Procesamiento Columna por Columna
  const stats: QuestionStats[] = keys.map(key => {
    let aciertos = 0;

