    const correctLetter = key.respuestaCorrecta;

    estudiantesData.forEach(student => {
      // Buscamos la columna en el objeto del estudiante que coincida con el ID
      const studentValue = clean(student[questionId]);

      if (studentValue === correctLetter && correctLetter !== '') {
        aciertos++;
      }
    });

    const porcentaje = totalStudents > 0 ? (aciertos / totalStudents) * 100 : 0;

