import * as XLSX from 'xlsx';
import { AnswerKey, Subject, ProcessedResults, QuestionStats } from '../types';

/**
 * Normaliza un valor a string, quitando espacios y pasando a mayúsculas para comparación estricta.
 */
const clean = (val: any): string => {
  if (val === null || val === undefined) return '';
  return String(val).trim().toUpperCase();
};

/**
 * Parsea el archivo Excel y normaliza las llaves de los objetos para que siempre sean strings.
 * Esto es crucial si las cabeceras son números (ej: 1, 2, 3), ya que sheet_to_json podría 
 * interpretarlos de forma inconsistente.
 */
export const parseExcelFile = async (file: File): Promise<any[]> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = new Uint8Array(e.target?.result as ArrayBuffer);
        const workbook = XLSX.read(data, { type: 'array' });
        const firstSheetName = workbook.SheetNames[0];
        const worksheet = workbook.Sheets[firstSheetName];

        // Obtenemos los datos brutos. Forzamos que los valores sean tratados de forma flexible.
        const rawJson: any[] = XLSX.utils.sheet_to_json(worksheet, { defval: "" });

        // Normalización de llaves: convertimos todas las cabeceras a String
        const normalizedJson = rawJson.map(row => {
          const newRow: any = {};
          Object.keys(row).forEach(key => {
            newRow[String(key).trim()] = row[key];
          });
          return newRow;
        });

        resolve(normalizedJson);
      } catch (err) {
        reject(err);
      }
    };
    reader.onerror = (err) => reject(err);
    reader.readAsArrayBuffer(file);
  });
};

export const processAcademicData = (
  estudiantesData: any[],
  respuestasData: any[]
): ProcessedResults => {
  // 1. Extraer la clave de respuestas analizando las columnas del segundo archivo
  const keys: AnswerKey[] = respuestasData.map(row => {
    const findValue = (possibleKeys: string[]) => {
      const foundKey = Object.keys(row).find(k => 
        possibleKeys.some(pk => k.toLowerCase().trim() === pk.toLowerCase().trim())
      );
      return foundKey ? row[foundKey] : null;
    };

    // Obtenemos el ID de la pregunta y la respuesta correcta
    // Usamos String() para asegurar que el ID de la pregunta sea comparable con las llaves de 'estudiantes'
    const preguntaIdRaw = findValue(['Pregunta id', 'ID', 'CODIGO', 'PREGUNTA', 'NÚMERO']);
    const preguntaId = preguntaIdRaw !== null ? String(preguntaIdRaw).trim() : '';

    const respuestaCorrectaRaw = findValue(['Respuesta Correcta', 'RESPUESTA', 'CLAVE', 'CORRECTA']);
    const respuestaCorrecta = clean(respuestaCorrectaRaw);

    const materiaStr = clean(findValue(['Área', 'Materia', 'Area', 'Asignatura'])).toLowerCase();

    // Clasificación por materia
    const materia = (materiaStr.includes('mat') || materiaStr.includes('math'))
      ? Subject.MATEMATICAS 
      : Subject.LENGUAJE;

    return {
      pregunta: preguntaId,
      respuestaCorrecta: respuestaCorrecta,
      materia: materia
    };
  }).filter(k => k.pregunta !== '' && k.respuestaCorrecta !== '');

  const totalStudents = estudiantesData.length;

  // 2. Ejecutar la lógica de "CONTAR.SI" para cada pregunta identificada
  const stats: QuestionStats[] = keys.map(key => {
    let aciertos = 0;

    const questionColumnName = key.pregunta; // Ej: "19"
    const targetLetter = key.respuestaCorrecta; // Ej: "C"

    estudiantesData.forEach(student => {
      // Obtenemos el valor de la celda en la columna correspondiente al ID de la pregunta
      const studentAnswer = clean(student[questionColumnName]);

      // Comparamos: Si la respuesta del estudiante (limpia) es igual a la correcta (limpia)
      if (studentAnswer === targetLetter) {
        aciertos++;
      }
    });

    const porcentaje = totalStudents > 0 ? (aciertos / totalStudents) * 100 : 0;

    return {
      pregunta: questionColumnName,
      materia: key.materia,
      aciertos: aciertos,
      total: totalStudents,
      porcentaje: porcentaje,
      respuestaCorrecta: targetLetter
    };
  });

  // 3. Cálculos de promedios para los dashboards
  const lenguajeStats = stats.filter(s => s.materia === Subject.LENGUAJE);
  const matematicasStats = stats.filter(s => s.materia === Subject.MATEMATICAS);

  const avgLenguaje = lenguajeStats.length > 0 
    ? lenguajeStats.reduce((acc, curr) => acc + curr.porcentaje, 0) / lenguajeStats.length 
    : 0;

  const avgMatematicas = matematicasStats.length > 0 
    ? matematicasStats.reduce((acc, curr) => acc + curr.porcentaje, 0) / matematicasStats.length 
    : 0;

  return {
    stats,
    totalStudents,
    avgLenguaje,
    avgMatematicas
  };
};

export enum Subject {
  LENGUAJE = 'Lenguaje',
  MATEMATICAS = 'Matemáticas'
}

export interface AnswerKey {
  pregunta: string;
  respuestaCorrecta: string;
  materia: Subject;
}

export interface OptionBreakdown {
  A: number;
  B: number;
  C: number;
  D: number;
  otros: number;
}

export interface QuestionStats {
  pregunta: string;
  materia: Subject;
  aciertos: number;
  total: number;
  porcentaje: number;
  respuestaCorrecta: string;
  distribucion: OptionBreakdown;
}

export interface ProcessedResults {
  stats: QuestionStats[];
  totalStudents: number;
  avgLenguaje: number;
  avgMatematicas: number;
}

