        {lenguajeStats.length > 0 && <StatTable title="Componente: Lenguaje" stats={lenguajeStats} color="emerald" />}
        {matematicasStats.length > 0 && <StatTable title="Componente: Matemáticas" stats={matematicasStats} color="blue" />}
      </div>
    </div>
  );
};

