export enum Subject {
  LENGUAJE = 'Lenguaje',
  MATEMATICAS = 'Matemáticas'
}

export interface AnswerKey {
  pregunta: string;
  respuestaCorrecta: string;
  materia: Subject;
}

export interface OptionBreakdown {
  A: number;
  B: number;
  C: number;
  D: number;
  otros: number;
}

export interface StudentAnswerDetail {
  nombre: string;
  grupo: string;
  respuestas: Record<string, string>; // ID Pregunta -> Respuesta del alumno
  aciertos: number;
}

export interface QuestionStats {
  pregunta: string;
  materia: Subject;
  aciertos: number;
  total: number;
  porcentaje: number;
  respuestaCorrecta: string;
  distribucion: OptionBreakdown;
}

export interface ProcessedResults {
  stats: QuestionStats[];
  students: StudentAnswerDetail[];
  totalStudents: number;
  avgLenguaje: number;
  avgMatematicas: number;
  detectedColumns: string[]; // Para depuración
}

import * as XLSX from 'xlsx';
import { AnswerKey, Subject, ProcessedResults, QuestionStats, OptionBreakdown, StudentAnswerDetail } from '../types';

/**
 * Normaliza un valor a string, quitando espacios y pasando a mayúsculas.
 */
const clean = (val: any): string => {
  if (val === null || val === undefined) return '';
  return String(val).trim().toUpperCase();
};

export const parseExcelFile = async (file: File): Promise<any[]> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = new Uint8Array(e.target?.result as ArrayBuffer);
        const workbook = XLSX.read(data, { type: 'array' });
        const firstSheetName = workbook.SheetNames[0];
        const worksheet = workbook.Sheets[firstSheetName];

        const rawJson: any[] = XLSX.utils.sheet_to_json(worksheet, { defval: "" });

        // Normalización de llaves (cabeceras) para evitar fallos por espacios
        const normalizedJson = rawJson.map(row => {
          const newRow: any = {};
          Object.keys(row).forEach(key => {
            newRow[String(key).trim()] = row[key];
          });
          return newRow;
        });

        resolve(normalizedJson);
      } catch (err) {
        reject(err);
      }
    };
    reader.onerror = (err) => reject(err);
    reader.readAsArrayBuffer(file);
  });
};

export const processAcademicData = (
  estudiantesData: any[],
  respuestasData: any[]
): ProcessedResults => {
  // 1. Obtener claves de respuestas
  const keys: AnswerKey[] = respuestasData.map(row => {
    const findValue = (possibleKeys: string[]) => {
      const foundKey = Object.keys(row).find(k => 
        possibleKeys.some(pk => k.toLowerCase().trim() === pk.toLowerCase().trim())
      );
      return foundKey ? row[foundKey] : null;
    };

    const preguntaIdRaw = findValue(['Pregunta id', 'ID', 'CODIGO', 'PREGUNTA', 'NÚMERO']);
    const preguntaId = preguntaIdRaw !== null ? String(preguntaIdRaw).trim() : '';

    const respuestaCorrectaRaw = findValue(['Respuesta Correcta', 'RESPUESTA', 'CLAVE', 'CORRECTA']);
    const respuestaCorrecta = clean(respuestaCorrectaRaw);

    const materiaStr = clean(findValue(['Área', 'Materia', 'Area', 'Asignatura'])).toLowerCase();
    const materia = (materiaStr.includes('mat') || materiaStr.includes('math'))
      ? Subject.MATEMATICAS 
      : Subject.LENGUAJE;

    return {
      pregunta: preguntaId,
      respuestaCorrecta: respuestaCorrecta,
      materia: materia
    };
  }).filter(k => k.pregunta !== '' && k.respuestaCorrecta !== '');

  // Columnas detectadas en el primer archivo (para depuración)
  const detectedColumns = estudiantesData.length > 0 ? Object.keys(estudiantesData[0]) : [];

  // 2. Procesar datos individuales de estudiantes y estadísticas por pregunta
  const stats: QuestionStats[] = keys.map(key => {
    let aciertos = 0;
    const distribucion: OptionBreakdown = { A: 0, B: 0, C: 0, D: 0, otros: 0 };
    const questionColumnName = key.pregunta;
    const targetLetter = key.respuestaCorrecta;

    estudiantesData.forEach(student => {
      const studentAnswer = clean(student[questionColumnName]);

      if (studentAnswer === 'A') distribucion.A++;
      else if (studentAnswer === 'B') distribucion.B++;
      else if (studentAnswer === 'C') distribucion.C++;
      else if (studentAnswer === 'D') distribucion.D++;
      else if (studentAnswer !== '') distribucion.otros++;

      if (studentAnswer === targetLetter) {
        aciertos++;
      }
    });

    return {
      pregunta: questionColumnName,
      materia: key.materia,
      aciertos,
      total: estudiantesData.length,
      porcentaje: estudiantesData.length > 0 ? (aciertos / estudiantesData.length) * 100 : 0,
      respuestaCorrecta: targetLetter,
      distribucion
    };
  });

  // 3. Crear detalle por estudiante
  const students: StudentAnswerDetail[] = estudiantesData.map(row => {
    // Intentamos encontrar el nombre y grupo
    const findInRow = (patterns: string[]) => {
      const key = Object.keys(row).find(k => patterns.some(p => k.toLowerCase().includes(p.toLowerCase())));
      return key ? String(row[key]).trim() : '';
    };

    const nombre = findInRow(['nombre', 'estudiante', 'alumno']);
    const grupo = findInRow(['grupo', 'grado', 'curso']);

    const studentRespuestas: Record<string, string> = {};
    let studentAciertos = 0;

    keys.forEach(key => {
      const ans = clean(row[key.pregunta]);
      studentRespuestas[key.pregunta] = ans;
      if (ans === key.respuestaCorrecta) {
        studentAciertos++;
      }
    });

    return {
      nombre: nombre || 'Estudiante sin nombre',
      grupo: grupo || '-',
      respuestas: studentRespuestas,
      aciertos: studentAciertos
    };
  });

  const lenguajeStats = stats.filter(s => s.materia === Subject.LENGUAJE);
  const matematicasStats = stats.filter(s => s.materia === Subject.MATEMATICAS);

  return {
    stats,
    students,
    totalStudents: estudiantesData.length,
    avgLenguaje: lenguajeStats.length > 0 ? lenguajeStats.reduce((a, b) => a + b.porcentaje, 0) / lenguajeStats.length : 0,
    avgMatematicas: matematicasStats.length > 0 ? matematicasStats.reduce((a, b) => a + b.porcentaje, 0) / matematicasStats.length : 0,
    detectedColumns
  };
};

