import React, { useState, useCallback } from 'react';
import FileUpload from './components/FileUpload';
import Dashboard from './components/Dashboard';
import { parseExcelFile, processAcademicData } from './utils/excelParser';
import { ProcessedResults } from './types';

const App: React.FC = () => {
  const [estudiantesFile, setEstudiantesFile] = useState<File | null>(null);
  const [respuestasFile, setRespuestasFile] = useState<File | null>(null);
  const [loading, setLoading] = useState(false);
  const [results, setResults] = useState<ProcessedResults | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleProcess = useCallback(async () => {
    if (!estudiantesFile || !respuestasFile) {
      setError("Por favor, sube ambos archivos para continuar.");
      return;
    }

    setLoading(true);
    setError(null);

    try {
      const [estudiantesData, respuestasData] = await Promise.all([
        parseExcelFile(estudiantesFile),
        parseExcelFile(respuestasFile)
      ]);

      if (estudiantesData.length === 0 || respuestasData.length === 0) {
        throw new Error("Uno de los archivos parece estar vacío.");
      }

      const processed = processAcademicData(estudiantesData, respuestasData);
      setResults(processed);
    } catch (err: any) {
      console.error(err);
      setError(`Error de procesamiento: ${err.message || "Asegúrate de que el archivo de respuestas tenga 'Pregunta id' y 'Respuesta Correcta'."}`);
    } finally {
      setLoading(false);
    }
  }, [estudiantesFile, respuestasFile]);

  const reset = () => {
    setEstudiantesFile(null);
    setRespuestasFile(null);
    setResults(null);
    setError(null);
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-10 shadow-sm">
