              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" />
              </svg>
            </div>
            <h1 className="text-2xl font-black text-slate-900 tracking-tight">EduAnalytica <span className="text-indigo-600">Audit</span></h1>
          </div>
          {results && (
            <button 
              onClick={reset}
              className="px-4 py-2 rounded-xl text-sm font-bold bg-indigo-50 text-indigo-600 hover:bg-indigo-100 transition-all flex items-center space-x-2 border border-indigo-100"
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
              </svg>
              <span>Reiniciar Análisis</span>
            </button>
          )}
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-grow max-w-7xl mx-auto w-full px-4 sm:px-6 lg:px-8 py-10">
        {!results ? (
          <div className="max-w-3xl mx-auto space-y-10 mt-6">
            <div className="text-center space-y-4">
              <h2 className="text-4xl font-black text-slate-900 sm:text-5xl tracking-tight leading-tight">
                Auditoría de Respuestas Académicas
              </h2>
              <p className="text-xl text-slate-500 max-w-xl mx-auto font-medium">
                Vincule sus archivos Excel para ver exactamente qué respondió cada estudiante y por qué los aciertos no coinciden.
              </p>
            </div>

            <div className="bg-white p-10 rounded-[3rem] shadow-2xl shadow-slate-200/60 border border-slate-100 space-y-8">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <FileUpload 
                  label="1. Estudiantes" 
                  description="Columnas 1-40 con respuestas"
                  accept=".xlsx, .xls, .csv"
                  onFileSelect={setEstudiantesFile}
                  selectedFileName={estudiantesFile?.name}
                />
                <FileUpload 
                  label="2. Respuestas" 
                  description="Clave: Pregunta ID + Correcta"
                  accept=".xlsx, .xls, .csv"
                  onFileSelect={setRespuestasFile}
                  selectedFileName={respuestasFile?.name}
                />
              </div>

              {error && (
                <div className="bg-rose-50 border border-rose-100 p-5 rounded-2xl flex items-start space-x-3">
                  <svg className="h-6 w-6 text-rose-500 flex-shrink-0" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
