import * as XLSX from 'xlsx';
import { AnswerKey, Subject, ProcessedResults, QuestionStats, OptionBreakdown, StudentAnswerDetail } from '../types';

/**
 * Normalización Profunda:
 * Convierte a String, quita espacios, pasa a mayúsculas y elimina decimales .0
 */
const superClean = (val: any): string => {
  if (val === null || val === undefined) return '';
  let str = String(val).trim().toUpperCase();
  // Eliminar el .0 que Excel pone a los números
  if (str.endsWith('.0')) str = str.substring(0, str.length - 2);
  // Eliminar prefijos comunes si el ID es solo un número
  return str;
};

/**
 * Crea un mapa de búsqueda para las columnas de estudiantes.
 * Esto permite encontrar "19" aunque la columna se llame "Pregunta 19" o "19.0".
 */
const createColumnMap = (firstRow: any): Record<string, string> => {
  const map: Record<string, string> = {};
  Object.keys(firstRow).forEach(originalKey => {
    const cleanedKey = superClean(originalKey);
    map[cleanedKey] = originalKey;

    // Si la cabecera contiene el número (ej: "P 19"), también mapeamos solo el número
    const numericMatch = cleanedKey.match(/\d+/);
    if (numericMatch) {
      const onlyNumber = numericMatch[0];
      if (!map[onlyNumber]) map[onlyNumber] = originalKey;
    }
  });
  return map;
};

export const parseExcelFile = async (file: File): Promise<any[]> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = new Uint8Array(e.target?.result as ArrayBuffer);
        const workbook = XLSX.read(data, { type: 'array' });
        const firstSheetName = workbook.SheetNames[0];
        const worksheet = workbook.Sheets[firstSheetName];
        // Forzamos a que todo sea tratado como texto inicialmente para evitar conversiones raras
        const rawJson: any[] = XLSX.utils.sheet_to_json(worksheet, { defval: "" });
        resolve(rawJson);
      } catch (err) {
        reject(err);
      }
    };
    reader.onerror = (err) => reject(err);
    reader.readAsArrayBuffer(file);
  });
};

export const processAcademicData = (
  estudiantesData: any[],
  respuestasData: any[]
): ProcessedResults => {
  if (estudiantesData.length === 0) throw new Error("Archivo de estudiantes vacío");

  // 1. Mapa de columnas de estudiantes para búsqueda rápida
  const studentColumnMap = createColumnMap(estudiantesData[0]);

  // 2. Extraer Claves de Respuestas
  const keys: AnswerKey[] = respuestasData.map(row => {
    const getVal = (names: string[]) => {
      const key = Object.keys(row).find(k => names.some(n => k.toLowerCase().includes(n.toLowerCase())));
      return key ? row[key] : null;
    };

    const rawId = getVal(['Pregunta id', 'ID', 'CODIGO', 'PREGUNTA', 'NÚMERO']);
    const id = superClean(rawId);
    const correcta = superClean(getVal(['Respuesta Correcta', 'RESPUESTA', 'CLAVE', 'CORRECTA']));
    const area = superClean(getVal(['Área', 'Materia', 'Area', 'Asignatura'])).toLowerCase();

    return {
      pregunta: id,
      respuestaCorrecta: correcta,
      materia: (area.includes('mat') || area.includes('math')) ? Subject.MATEMATICAS : Subject.LENGUAJE
    };
  }).filter(k => k.pregunta !== '' && k.respuestaCorrecta !== '');

  // 3. Procesar Estadísticas con el mapa de columnas
  const stats: QuestionStats[] = keys.map(key => {
    let aciertos = 0;
    const distribucion: OptionBreakdown = { A: 0, B: 0, C: 0, D: 0, otros: 0 };

    // Buscamos cuál es la columna real en el archivo de estudiantes que corresponde a este ID
    const actualColumnName = studentColumnMap[key.pregunta];
    const targetCorrect = key.respuestaCorrecta;

    if (actualColumnName) {
      estudiantesData.forEach(student => {
        const rawAns = student[actualColumnName];
        const ans = superClean(rawAns);

        if (ans === 'A') distribucion.A++;
        else if (ans === 'B') distribucion.B++;
        else if (ans === 'C') distribucion.C++;
        else if (ans === 'D') distribucion.D++;
        else if (ans !== '') distribucion.otros++;

        if (ans === targetCorrect) {
          aciertos++;
        }
      });
    }

    return {
      pregunta: key.pregunta,
      materia: key.materia,
      aciertos,
      total: estudiantesData.length,
      porcentaje: estudiantesData.length > 0 ? (aciertos / estudiantesData.length) * 100 : 0,
      respuestaCorrecta: targetCorrect,
      distribucion
    };
  });

  // 4. Detalle Individual por Estudiante
  const students: StudentAnswerDetail[] = estudiantesData.map(row => {
    const getVal = (names: string[]) => {
      const key = Object.keys(row).find(k => names.some(n => k.toLowerCase().includes(n.toLowerCase())));
      return key ? String(row[key]).trim() : '';
    };

    const studentRespuestas: Record<string, string> = {};
    let studentAciertos = 0;

    keys.forEach(key => {
      const actualCol = studentColumnMap[key.pregunta];
      const ans = actualCol ? superClean(row[actualCol]) : '';
      studentRespuestas[key.pregunta] = ans;
      if (ans === key.respuestaCorrecta) studentAciertos++;
    });

    return {
      nombre: getVal(['nombre', 'estudiante', 'alumno']) || 'Estudiante Anónimo',
      grupo: getVal(['grupo', 'grado', 'curso']) || '-',
      respuestas: studentRespuestas,
      aciertos: studentAciertos
    };
  });

  const lenguajeStats = stats.filter(s => s.materia === Subject.LENGUAJE);
  const matematicasStats = stats.filter(s => s.materia === Subject.MATEMATICAS);

  return {
    stats,
    students,
    totalStudents: estudiantesData.length,
    avgLenguaje: lenguajeStats.length > 0 ? lenguajeStats.reduce((a, b) => a + b.porcentaje, 0) / lenguajeStats.length : 0,
    avgMatematicas: matematicasStats.length > 0 ? matematicasStats.reduce((a, b) => a + b.porcentaje, 0) / matematicasStats.length : 0,
    detectedColumns: Object.keys(studentColumnMap)
  };
};

export const downloadResultsAsExcel = (results: QuestionStats[]) => {
  const data = results.map((s, idx) => ({
    'Orden': idx + 1,
    'Pregunta ID': s.pregunta,
    'Componente': s.materia,
    'Clave Correcta': s.respuestaCorrecta,
    'Total Aciertos': s.aciertos,
    '% Éxito': `${s.porcentaje.toFixed(1)}%`
  }));

  const worksheet = XLSX.utils.json_to_sheet(data);
  const workbook = XLSX.utils.book_new();
