import * as XLSX from 'xlsx';
import { AnswerKey, Subject, ProcessedResults, QuestionStats, OptionBreakdown, StudentAnswerDetail } from '../types';

/**
 * Normalización Ultrasensible:
 * Limpia el texto de espacios, saltos de línea, lo pasa a mayúsculas 
 * y quita el formato numérico de Excel (.0)
 */
const ultraClean = (val: any): string => {
  if (val === null || val === undefined) return '';
  let str = String(val).trim().toUpperCase();
  // Elimina .0 al final (común en IDs numéricos de Excel)
  if (str.endsWith('.0')) str = str.substring(0, str.length - 2);
  // Quita ceros a la izquierda para IDs (ej: "01" -> "1")
  if (/^\d+$/.test(str)) str = parseInt(str, 10).toString();
  return str;
};

/**
 * Genera un mapa de columnas del archivo de estudiantes.
 * Permite que el ID "19" coincida con la columna "19", "019", "Pregunta 19", etc.
 */
const createSmartColumnMap = (headers: string[]): Record<string, string> => {
  const map: Record<string, string> = {};
  headers.forEach(header => {
    const cleaned = ultraClean(header);
    map[cleaned] = header;

    // Si la cabecera tiene texto y números, extraemos solo el número
    const numbers = cleaned.match(/\d+/);
    if (numbers) {
      const numOnly = ultraClean(numbers[0]);
      if (!map[numOnly]) map[numOnly] = header;
    }
  });
  return map;
};

export const parseExcelFile = async (file: File): Promise<any[]> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = new Uint8Array(e.target?.result as ArrayBuffer);
        const workbook = XLSX.read(data, { type: 'array' });
        const firstSheetName = workbook.SheetNames[0];
        const worksheet = workbook.Sheets[firstSheetName];
        const rawJson: any[] = XLSX.utils.sheet_to_json(worksheet, { defval: "" });
        resolve(rawJson);
      } catch (err) {
        reject(err);
      }
    };
    reader.onerror = (err) => reject(err);
    reader.readAsArrayBuffer(file);
  });
};

export const processAcademicData = (
  estudiantesData: any[],
  respuestasData: any[]
): ProcessedResults => {
  if (estudiantesData.length === 0) throw new Error("El archivo de estudiantes no tiene datos.");

  // 1. Analizar cabeceras del archivo de estudiantes
  const studentHeaders = Object.keys(estudiantesData[0]);
  const smartMap = createSmartColumnMap(studentHeaders);

  // 2. Extraer Clave de Respuestas (Tabla de Referencia)
  const answersTable: AnswerKey[] = respuestasData.map(row => {
    const find = (keywords: string[]) => {
      const key = Object.keys(row).find(k => keywords.some(kw => k.toLowerCase().includes(kw.toLowerCase())));
      return key ? row[key] : null;
    };

    const id = ultraClean(find(['id', 'pregunta', 'codigo', 'numero']));
    const correcta = ultraClean(find(['correcta', 'respuesta', 'clave']));
    const area = ultraClean(find(['materia', 'area', 'asignatura'])).toLowerCase();

    return {
      pregunta: id,
      respuestaCorrecta: correcta,
      materia: (area.includes('mat') || area.includes('math')) ? Subject.MATEMATICAS : Subject.LENGUAJE
    };
  }).filter(k => k.pregunta !== '' && k.respuestaCorrecta !== '');

  // 3. Procesar Conteo de Coincidencias (Lógica de Calificación)
  const stats: QuestionStats[] = answersTable.map(key => {
    let matchesCount = 0;
    const dist: OptionBreakdown = { A: 0, B: 0, C: 0, D: 0, otros: 0 };

    // Identificar la columna real en el Excel de estudiantes
    const targetColumn = smartMap[key.pregunta];
    const expectedValue = key.respuestaCorrecta;

    if (targetColumn) {
      estudiantesData.forEach(student => {
        const studentValue = ultraClean(student[targetColumn]);

        // Conteo de distribución
        if (studentValue === 'A') dist.A++;
        else if (studentValue === 'B') dist.B++;
        else if (studentValue === 'C') dist.C++;
        else if (studentValue === 'D') dist.D++;
        else if (studentValue !== '') dist.otros++;

        // CONTEO DE COINCIDENCIAS (ACIERTO)
        if (studentValue === expectedValue) {
          matchesCount++;
        }
      });
    }

    return {
      pregunta: key.pregunta,
      materia: key.materia,
      aciertos: matchesCount,
      total: estudiantesData.length,
      porcentaje: estudiantesData.length > 0 ? (matchesCount / estudiantesData.length) * 100 : 0,
      respuestaCorrecta: expectedValue,
      distribucion: dist
    };
  });

  // 4. Detalle Individual de Estudiantes
  const students: StudentAnswerDetail[] = estudiantesData.map(row => {
    const findInRow = (keywords: string[]) => {
      const key = Object.keys(row).find(k => keywords.some(kw => k.toLowerCase().includes(kw.toLowerCase())));
      return key ? String(row[key]).trim() : '';
    };

    const studentAnswersMap: Record<string, string> = {};
    let totalScore = 0;

    answersTable.forEach(key => {
      const col = smartMap[key.pregunta];
      const ans = col ? ultraClean(row[col]) : '';
      studentAnswersMap[key.pregunta] = ans;
      if (ans === key.respuestaCorrecta) totalScore++;
    });

    return {
      nombre: findInRow(['nombre', 'estudiante', 'alumno']) || 'Alumno sin nombre',
      grupo: findInRow(['grupo', 'grado', 'curso']) || '-',
      respuestas: studentAnswersMap,
      aciertos: totalScore
    };
  });

  const lengStats = stats.filter(s => s.materia === Subject.LENGUAJE);
  const mathStats = stats.filter(s => s.materia === Subject.MATEMATICAS);

  return {
    stats,
    students,
    totalStudents: estudiantesData.length,
    avgLenguaje: lengStats.length > 0 ? lengStats.reduce((a, b) => a + b.porcentaje, 0) / lengStats.length : 0,
    avgMatematicas: mathStats.length > 0 ? mathStats.reduce((a, b) => a + b.porcentaje, 0) / mathStats.length : 0,
    detectedColumns: Object.keys(smartMap)
  };
};

export const downloadResultsAsExcel = (results: QuestionStats[]) => {
  const data = results.map((s, idx) => ({
    'No.': idx + 1,
    'ID Pregunta': s.pregunta,
    'Materia': s.materia,
    'Clave Correcta': s.respuestaCorrecta,
    'Total Estudiantes con Acierto': s.aciertos,
    'Total Alumnos': s.total,
    '% Acierto': `${s.porcentaje.toFixed(1)}%`
  }));

  const worksheet = XLSX.utils.json_to_sheet(data);
  const workbook = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(workbook, worksheet, "Conteo de Aciertos");
  XLSX.writeFile(workbook, "Reporte_Frecuencias_Aciertos.xlsx");
};

