import * as XLSX from 'xlsx';
import { AnswerKey, Subject, ProcessedResults, QuestionStats, OptionBreakdown, StudentAnswerDetail } from '../types';

/**
 * Normalización extrema para IDs y Respuestas:
 * - Elimina todo lo que no sea alfanumérico si es necesario.
 * - Quita sufijos de Excel como ".0".
 * - Quita puntos y paréntesis (ej: "A." -> "A", "1)" -> "1").
 */
const extremeClean = (val: any): string => {
  if (val === null || val === undefined) return '';
  let str = String(val).trim().toUpperCase();

  // Quitar el molesto .0 de Excel
  if (str.endsWith('.0')) str = str.substring(0, str.length - 2);

  // Quitar caracteres de formato comunes en respuestas (A., B), 1., etc.)
  // Si el string es algo como "A." o "(A)", nos quedamos solo con "A"
  str = str.replace(/^[^\w]+|[^\w]+$/g, ''); 

  // Quitar ceros a la izquierda si es un número puro
  if (/^\d+$/.test(str)) {
    str = parseInt(str, 10).toString();
  }

  return str;
};

/**
 * Busca una columna de manera inteligente. 
 * Si buscamos "19", intentará encontrar "19", "P19", "PREGUNTA 19", "019", etc.
 */
const findBestColumn = (headers: string[], targetId: string): string | undefined => {
  const target = extremeClean(targetId);

  // 1. Coincidencia exacta tras limpieza
  const exact = headers.find(h => extremeClean(h) === target);
  if (exact) return exact;

  // 2. Coincidencia parcial (que el encabezado contenga el número/id)
  const partial = headers.find(h => {
    const hClean = extremeClean(h);
    return hClean === target || hClean.includes(target) || target.includes(hClean);
  });

  return partial;
};

export const parseExcelFile = async (file: File): Promise<any[]> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = new Uint8Array(e.target?.result as ArrayBuffer);
        const workbook = XLSX.read(data, { type: 'array' });
        const firstSheetName = workbook.SheetNames[0];
        const worksheet = workbook.Sheets[firstSheetName];

        // Convertimos a JSON. Usamos defval para no tener undefined.
        // Si el archivo tiene filas vacías al inicio, sheet_to_json suele manejarlas,
        // pero aquí forzamos la lectura desde la fila 1 (A1).
        const rawJson: any[] = XLSX.utils.sheet_to_json(worksheet, { defval: "" });
        resolve(rawJson);
      } catch (err) {
        reject(err);
      }
    };
    reader.onerror = (err) => reject(err);
    reader.readAsArrayBuffer(file);
  });
};

export const processAcademicData = (
  estudiantesData: any[],
  respuestasData: any[]
): ProcessedResults => {
  if (estudiantesData.length === 0) throw new Error("El archivo de estudiantes está vacío.");

  // Obtenemos todas las cabeceras disponibles en el archivo de estudiantes
  const studentHeaders = Object.keys(estudiantesData[0]);

  // 1. Procesar la Clave de Respuestas
  const answersTable: AnswerKey[] = respuestasData.map(row => {
    const find = (keywords: string[]) => {
      const key = Object.keys(row).find(k => keywords.some(kw => k.toLowerCase().includes(kw.toLowerCase())));
      return key ? row[key] : null;
    };

    const idRaw = find(['id', 'pregunta', 'codigo', 'numero']);
    const correctaRaw = find(['correcta', 'respuesta', 'clave']);
    const areaRaw = find(['materia', 'area', 'asignatura']);

    return {
      pregunta: extremeClean(idRaw),
      respuestaCorrecta: extremeClean(correctaRaw),
      materia: String(areaRaw || '').toLowerCase().includes('mat') ? Subject.MATEMATICAS : Subject.LENGUAJE
    };
  }).filter(k => k.pregunta !== '' && k.respuestaCorrecta !== '');

  // 2. Calcular Estadísticas y CONTEO DE ACIERTOS
  const stats: QuestionStats[] = answersTable.map(key => {
    let matchesCount = 0;
    const dist: OptionBreakdown = { A: 0, B: 0, C: 0, D: 0, otros: 0 };

    // IMPORTANTE: Encontrar la columna real
    const targetColumn = findBestColumn(studentHeaders, key.pregunta);
    const expectedValue = key.respuestaCorrecta;

    if (targetColumn) {
      estudiantesData.forEach(student => {
        const rawVal = student[targetColumn];
        const studentValue = extremeClean(rawVal);

        // Llenar distribución
        if (studentValue === 'A') dist.A++;
        else if (studentValue === 'B') dist.B++;
        else if (studentValue === 'C') dist.C++;
        else if (studentValue === 'D') dist.D++;
        else if (studentValue !== '') dist.otros++;

        // EL CONTEO CRÍTICO: Comparamos valores normalizados
        if (studentValue === expectedValue && expectedValue !== '') {
          matchesCount++;
        }
      });
    }

    return {
      pregunta: key.pregunta,
      materia: key.materia,
      aciertos: matchesCount,
      total: estudiantesData.length,
      porcentaje: estudiantesData.length > 0 ? (matchesCount / estudiantesData.length) * 100 : 0,
      respuestaCorrecta: expectedValue,
      distribucion: dist
    };
  });

  // 3. Detalle Estudiantil
  const students: StudentAnswerDetail[] = estudiantesData.map(row => {
    const getField = (keywords: string[]) => {
      const key = Object.keys(row).find(k => keywords.some(kw => k.toLowerCase().includes(kw.toLowerCase())));
      return key ? String(row[key]).trim() : '';
    };

    const studentAnswersMap: Record<string, string> = {};
    let studentScore = 0;

    answersTable.forEach(key => {
      const col = findBestColumn(studentHeaders, key.pregunta);
      const val = col ? extremeClean(row[col]) : '';
      studentAnswersMap[key.pregunta] = val;
      if (val === key.respuestaCorrecta && val !== '') {
        studentScore++;
      }
    });

    return {
      nombre: getField(['nombre', 'estudiante', 'alumno']) || 'Alumno N/A',
      grupo: getField(['grupo', 'grado', 'curso', 'seccion']) || '-',
      respuestas: studentAnswersMap,
      aciertos: studentScore
    };
  });

  const lengStats = stats.filter(s => s.materia === Subject.LENGUAJE);
  const mathStats = stats.filter(s => s.materia === Subject.MATEMATICAS);

  return {
    stats,
    students,
    totalStudents: estudiantesData.length,
    avgLenguaje: lengStats.length > 0 ? lengStats.reduce((a, b) => a + b.porcentaje, 0) / lengStats.length : 0,
    avgMatematicas: mathStats.length > 0 ? mathStats.reduce((a, b) => a + b.porcentaje, 0) / mathStats.length : 0,
    detectedColumns: studentHeaders
  };
};

export const downloadResultsAsExcel = (results: QuestionStats[]) => {
  const data = results.map((s, idx) => ({
    'Nº': idx + 1,
    'Pregunta': s.pregunta,
    'Materia': s.materia,
    'Respuesta Correcta': s.respuestaCorrecta,
    'Aciertos Hallados': s.aciertos,
    'Total Estudiantes': s.total,
    '% de Éxito': `${s.porcentaje.toFixed(1)}%`
  }));

  const worksheet = XLSX.utils.json_to_sheet(data);
  const workbook = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(workbook, worksheet, "Reporte");
  XLSX.writeFile(workbook, "EduAnalytica_Resultados.xlsx");
};

