import * as XLSX from 'xlsx';
import { AnswerKey, Subject, ProcessedResults, QuestionStats, OptionBreakdown, StudentAnswerDetail } from '../types';

/**
 * Normaliza valores para comparación total.
 * Convierte cualquier entrada a un String limpio, sin decimales de Excel,
 * sin puntos finales, sin paréntesis y en mayúsculas.
 */
const normalize = (val: any): string => {
  if (val === null || val === undefined) return '';
  let str = String(val).trim().toUpperCase();

  // Eliminar el .0 que Excel añade a números (ej: "19.0" -> "19")
  if (str.endsWith('.0')) str = str.substring(0, str.length - 2);

  // Eliminar caracteres de decoración (ej: "A." -> "A", "(B)" -> "B", "1-" -> "1")
  str = str.replace(/[^A-Z0-9]/g, '');

  // Si es un número con ceros a la izquierda, quitar ceros (ej: "001" -> "1")
  if (/^\d+$/.test(str)) {
    str = parseInt(str, 10).toString();
  }

  return str;
};

export const parseExcelFile = async (file: File): Promise<any[]> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => {
