        const workbook = XLSX.read(data, { type: 'array' });
        const firstSheet = workbook.Sheets[workbook.SheetNames[0]];

        // Obtenemos los datos ignorando filas vacías iniciales
        const rawJson: any[] = XLSX.utils.sheet_to_json(firstSheet, { 
          defval: "",
          blankrows: false 
        });
        resolve(rawJson);
      } catch (err) {
        reject(err);
      }
    };
    reader.onerror = (err) => reject(err);
    reader.readAsArrayBuffer(file);
  });
};

export const processAcademicData = (
  estudiantesData: any[],
  respuestasData: any[]
): ProcessedResults => {
  if (!estudiantesData.length) throw new Error("No hay datos en Estudiantes");

  // 1. Obtener los encabezados reales de Estudiantes
  const studentColumns = Object.keys(estudiantesData[0]);

  // 2. Crear Mapa de Claves (ID -> Respuesta Correcta)
  const answersMap = new Map<string, { correcta: string; materia: Subject }>();
  respuestasData.forEach(row => {
    const findInRow = (keys: string[]) => {
      const k = Object.keys(row).find(rk => keys.some(key => rk.toLowerCase().includes(key)));
      return k ? row[k] : null;
    };

    const id = normalize(findInRow(['id', 'pregunta', 'codigo', 'numero']));
    const correcta = normalize(findInRow(['correcta', 'respuesta', 'clave']));
    const area = String(findInRow(['materia', 'area', 'asignatura']) || '').toLowerCase();

    if (id && correcta) {
      answersMap.set(id, {
        correcta,
        materia: area.includes('mat') ? Subject.MATEMATICAS : Subject.LENGUAJE
      });
    }
  });

  // 3. Procesar cada pregunta basándonos en lo que hay en ESTUDIANTES
  const stats: QuestionStats[] = [];
  const processedQuestionIds: string[] = [];

  // Buscamos columnas que coincidan con IDs de nuestra clave
  studentColumns.forEach(colName => {
    const normalizedCol = normalize(colName);
    const keyData = answersMap.get(normalizedCol);

    if (keyData) {
      let aciertos = 0;
      const dist: OptionBreakdown = { A: 0, B: 0, C: 0, D: 0, otros: 0 };
      const total = estudiantesData.length;

      estudiantesData.forEach(student => {
        const rawVal = student[colName];
        const studentAns = normalize(rawVal);

        // Conteo de distribución
        if (studentAns === 'A') dist.A++;
        else if (studentAns === 'B') dist.B++;
        else if (studentAns === 'C') dist.C++;
        else if (studentAns === 'D') dist.D++;
        else if (studentAns !== '') dist.otros++;

        // CONTEO DE COINCIDENCIAS (El núcleo de tu petición)
        if (studentAns !== '' && studentAns === keyData.correcta) {
          aciertos++;
        }
      });

      stats.push({
        pregunta: normalizedCol, // ID de la pregunta
        materia: keyData.materia,
        aciertos,
        total,
        porcentaje: (aciertos / total) * 100,
        respuestaCorrecta: keyData.correcta,
        distribucion: dist
      });
      processedQuestionIds.push(normalizedCol);
    }
  });

  // 4. Generar Auditoría Individual
  const students: StudentAnswerDetail[] = estudiantesData.map(row => {
    const findName = (keys: string[]) => {
      const k = Object.keys(row).find(rk => keys.some(key => rk.toLowerCase().includes(key)));
      return k ? String(row[k]) : 'Estudiante N/A';
    };

    const studentAnswers: Record<string, string> = {};
    let studentAciertos = 0;

    processedQuestionIds.forEach(id => {
      // Buscamos la columna original que mapeó a este ID
      const originalCol = studentColumns.find(c => normalize(c) === id);
      if (originalCol) {
        const ans = normalize(row[originalCol]);
        const key = answersMap.get(id);
        studentAnswers[id] = ans;
        if (ans !== '' && key && ans === key.correcta) {
          studentAciertos++;
        }
      }
    });

    return {
      nombre: findName(['nombre', 'alumno', 'estudiante']),
      grupo: findName(['grupo', 'grado', 'curso', 'seccion']),
      respuestas: studentAnswers,
      aciertos: studentAciertos
    };
  });

  const leng = stats.filter(s => s.materia === Subject.LENGUAJE);
  const math = stats.filter(s => s.materia === Subject.MATEMATICAS);

  return {
    stats,
    students,
    totalStudents: estudiantesData.length,
    avgLenguaje: leng.length ? leng.reduce((a, b) => a + b.porcentaje, 0) / leng.length : 0,
    avgMatematicas: math.length ? math.reduce((a, b) => a + b.porcentaje, 0) / math.length : 0,
    detectedColumns: studentColumns
  };
};

