import * as XLSX from 'xlsx';
import { AnswerKey, Subject, ProcessedResults, QuestionStats, OptionBreakdown, StudentAnswerDetail } from '../types';

/**
 * Normalización de Alto Alcance:
 * Convierte cualquier valor a una cadena "pura" (solo letras y números básicos).
 * Elimina decimales de Excel, ceros a la izquierda, puntos, paréntesis y espacios.
 */
const deepNormalize = (val: any): string => {
  if (val === null || val === undefined) return '';
  let str = String(val).trim().toUpperCase();

  // Eliminar .0 al final (formatos numéricos de Excel)
  if (str.endsWith('.0')) str = str.substring(0, str.length - 2);

  // Extraer solo la parte alfanumérica relevante (ej: "Pregunta 01" -> "1", "A." -> "A")
  // Si el valor contiene números, nos quedamos solo con los números (para IDs)
  // Si es una respuesta (letra), nos quedamos con la letra.
  const numbers = str.match(/\d+/);
  if (numbers && str.length > 0 && !/^[A-Z]$/.test(str)) {
    return parseInt(numbers[0], 10).toString();
  }

  // Limpieza para letras de respuestas (ej: "A." -> "A")
  return str.replace(/[^A-Z0-9]/g, '');
};

export const parseExcelFile = async (file: File): Promise<any[]> => {
  return new Promise((resolve, reject) => {
