        const workbook = XLSX.read(data, { type: 'array' });
        const worksheet = workbook.Sheets[workbook.SheetNames[0]];
        const rawJson: any[] = XLSX.utils.sheet_to_json(worksheet, { defval: "", blankrows: false });
        resolve(rawJson);
      } catch (err) {
        reject(err);
      }
    };
    reader.onerror = (err) => reject(err);
    reader.readAsArrayBuffer(file);
  });
};

export const processAcademicData = (
  estudiantesData: any[],
  respuestasData: any[]
): ProcessedResults => {
  if (estudiantesData.length === 0) throw new Error("El archivo de estudiantes está vacío.");

  // 1. Mapear todas las cabeceras del archivo de Estudiantes
  const studentHeaders = Object.keys(estudiantesData[0]);

  // 2. Indexar la Clave de Respuestas para búsqueda rápida
  const keyLookup = new Map<string, { correcta: string; materia: Subject }>();
  respuestasData.forEach(row => {
    const getVal = (names: string[]) => {
      const key = Object.keys(row).find(k => names.some(n => k.toLowerCase().includes(n.toLowerCase())));
      return key ? row[key] : null;
    };

    const id = deepNormalize(getVal(['id', 'pregunta', 'codigo', 'numero', 'item']));
    const correcta = deepNormalize(getVal(['correcta', 'respuesta', 'clave']));
    const area = String(getVal(['materia', 'area', 'asignatura', 'componente']) || '').toLowerCase();

    if (id && correcta) {
      keyLookup.set(id, {
        correcta,
        materia: (area.includes('mat') || area.includes('calculo')) ? Subject.MATEMATICAS : Subject.LENGUAJE
      });
    }
  });

  // 3. EVALUAR TODAS LAS PREGUNTAS DETECTADAS EN ESTUDIANTES
  const stats: QuestionStats[] = [];
  const validQuestionColumns: string[] = [];

  studentHeaders.forEach(header => {
    const normalizedHeader = deepNormalize(header);
    const keyInfo = keyLookup.get(normalizedHeader);

    // Consideramos una columna como "Pregunta" si está en la clave o si es puramente numérica
    // (para reportar incluso si no tiene clave asociada)
    const isNumericHeader = /^\d+$/.test(normalizedHeader);

    if (keyInfo || isNumericHeader) {
      validQuestionColumns.push(header);

      let matchCount = 0;
      const distribution: OptionBreakdown = { A: 0, B: 0, C: 0, D: 0, otros: 0 };
      const expected = keyInfo?.correcta || '';

      estudiantesData.forEach(student => {
        const studentRaw = student[header];
        const studentVal = deepNormalize(studentRaw);

        // Llenado de distribución de opciones
        if (['A', 'B', 'C', 'D'].includes(studentVal)) {
          distribution[studentVal as keyof OptionBreakdown]++;
        } else if (studentVal !== '') {
          distribution.otros++;
        }

        // CONTEO DE ACIERTOS (Comparación Estricta Normalizada)
        if (expected !== '' && studentVal === expected) {
          matchCount++;
        }
      });

      stats.push({
        pregunta: normalizedHeader,
        materia: keyInfo?.materia || Subject.LENGUAJE,
        aciertos: matchCount,
        total: estudiantesData.length,
        porcentaje: estudiantesData.length > 0 ? (matchCount / estudiantesData.length) * 100 : 0,
        respuestaCorrecta: expected,
        distribucion: distribution
      });
    }
  });

  // Ordenar estadísticas por ID numérico si es posible
  stats.sort((a, b) => {
    const numA = parseInt(a.pregunta);
    const numB = parseInt(b.pregunta);
    return (!isNaN(numA) && !isNaN(numB)) ? numA - numB : a.pregunta.localeCompare(b.pregunta);
  });

  // 4. Detalle por Estudiante (Auditoría)
  const students: StudentAnswerDetail[] = estudiantesData.map(row => {
    const findField = (names: string[]) => {
      const k = Object.keys(row).find(key => names.some(n => key.toLowerCase().includes(n.toLowerCase())));
      return k ? String(row[k]) : '';
    };

    const studentAnswers: Record<string, string> = {};
    let studentAciertos = 0;

    stats.forEach(stat => {
      // Buscamos el valor original en la columna que corresponde a esta pregunta
      const originalCol = validQuestionColumns.find(c => deepNormalize(c) === stat.pregunta);
      if (originalCol) {
        const val = deepNormalize(row[originalCol]);
        studentAnswers[stat.pregunta] = val;
        if (stat.respuestaCorrecta !== '' && val === stat.respuestaCorrecta) {
          studentAciertos++;
        }
      }
    });

    return {
      nombre: findField(['nombre', 'estudiante', 'alumno', 'participante']) || 'Anónimo',
      grupo: findField(['grupo', 'grado', 'curso', 'seccion', 'aula']) || '-',
      respuestas: studentAnswers,
      aciertos: studentAciertos
    };
  });

  const leng = stats.filter(s => s.materia === Subject.LENGUAJE);
  const math = stats.filter(s => s.materia === Subject.MATEMATICAS);

  return {
    stats,
    students,
    totalStudents: estudiantesData.length,
    avgLenguaje: leng.length > 0 ? leng.reduce((a, b) => a + b.porcentaje, 0) / leng.length : 0,
    avgMatematicas: math.length > 0 ? math.reduce((a, b) => a + b.porcentaje, 0) / math.length : 0,
    detectedColumns: studentHeaders
  };
};

