import * as XLSX from 'xlsx';
import { AnswerKey, Subject, ProcessedResults, QuestionStats, OptionBreakdown, StudentAnswerDetail } from '../types';

/**
 * Normalización Ultra-Agresiva:
 * Convierte cualquier valor (ID o Respuesta) a su forma más pura.
 * Elimina: .0 de Excel, espacios, paréntesis, puntos, ceros a la izquierda.
 * Ejemplos: "01." -> "1", "(A)" -> "A", "Pregunta 19" -> "19", "A." -> "A".
 */
const extremeNormalize = (val: any): string => {
  if (val === null || val === undefined) return '';
  let str = String(val).trim().toUpperCase();

  // Quitar sufijo decimal de Excel .0
  if (str.endsWith('.0')) str = str.substring(0, str.length - 2);

  // Si el valor es una sola letra (A, B, C, D) seguida de basura o sola
  const singleLetterMatch = str.match(/^[A-Z](?![A-Z0-9])/);
  if (singleLetterMatch) return singleLetterMatch[0];

  // Si el valor contiene números, extraemos el primer grupo de números (para IDs de preguntas)
  const numbers = str.match(/\d+/);
  if (numbers) {
    return parseInt(numbers[0], 10).toString();
  }

  // Si no hay números ni es letra sola, quitamos caracteres especiales y devolvemos lo que quede
  return str.replace(/[^A-Z0-9]/g, '');
};

export const parseExcelFile = async (file: File): Promise<any[]> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = new Uint8Array(e.target?.result as ArrayBuffer);
        const workbook = XLSX.read(data, { type: 'array' });
        const sheet = workbook.Sheets[workbook.SheetNames[0]];
        // Leemos ignorando filas vacías y forzando a que todo sea texto para evitar redondeos extraños
        const rawJson: any[] = XLSX.utils.sheet_to_json(sheet, { 
          defval: "", 
          raw: false,
          blankrows: false 
        });
        resolve(rawJson);
      } catch (err) {
        reject(err);
      }
    };
    reader.onerror = (err) => reject(err);
    reader.readAsArrayBuffer(file);
  });
};

export const processAcademicData = (
  estudiantesData: any[],
  respuestasData: any[]
): ProcessedResults => {
  if (estudiantesData.length === 0) throw new Error("El archivo de estudiantes no contiene datos procesables.");

  // 1. Obtener todas las columnas del archivo de Estudiantes
  const studentHeaders = Object.keys(estudiantesData[0]);

  // 2. Crear un mapa de búsqueda de la Clave de Respuestas (ID -> {Correcta, Materia})
  const keyLookup = new Map<string, { correcta: string; materia: Subject }>();
  respuestasData.forEach(row => {
    const findValue = (possibleNames: string[]) => {
      const key = Object.keys(row).find(k => possibleNames.some(name => k.toLowerCase().includes(name)));
      return key ? row[key] : null;
    };

    const idRaw = findValue(['id', 'pregunta', 'item', 'codigo', 'numero']);
    const correctaRaw = findValue(['correcta', 'respuesta', 'clave']);
    const materiaRaw = String(findValue(['materia', 'area', 'asignatura', 'lengua']) || '').toLowerCase();

    const cleanId = extremeNormalize(idRaw);
    const cleanCorrecta = extremeNormalize(correctaRaw);

    if (cleanId && cleanCorrecta) {
      keyLookup.set(cleanId, {
        correcta: cleanCorrecta,
        materia: (materiaRaw.includes('mat') || materiaRaw.includes('calc')) ? Subject.MATEMATICAS : Subject.LENGUAJE
      });
    }
  });

  // 3. SEGUIR EL FLUJO: Recorrer columnas de ESTUDIANTES -> Buscar Clave -> Contar
  const stats: QuestionStats[] = [];
  const processedQuestionsMap = new Map<string, string>(); // ID Normalizado -> Columna Original en Excel

  studentHeaders.forEach(colName => {
    const normCol = extremeNormalize(colName);
    const key = keyLookup.get(normCol);

    // Si la columna parece ser una pregunta (tiene número o está en la clave)
    if (key || /^\d+$/.test(normCol)) {
      processedQuestionsMap.set(normCol, colName);

      let coincidenciaTotal = 0;
      const distribution: OptionBreakdown = { A: 0, B: 0, C: 0, D: 0, otros: 0 };
      const correctaEsperada = key?.correcta || '';

      // Regresamos a evaluar cada fila de esa misma columna en Estudiantes
      estudiantesData.forEach(row => {
        const studentValueRaw = row[colName];
        const studentValueClean = extremeNormalize(studentValueRaw);

        // Conteo de distribución
        if (['A', 'B', 'C', 'D'].includes(studentValueClean)) {
          distribution[studentValueClean as keyof OptionBreakdown]++;
        } else if (studentValueClean !== '') {
          distribution.otros++;
        }

        // EL CONTEO CRÍTICO: ¿Coincide con la respuesta correcta?
        if (correctaEsperada !== '' && studentValueClean === correctaEsperada) {
          coincidenciaTotal++;
        }
      });

      stats.push({
        pregunta: normCol,
        materia: key?.materia || Subject.LENGUAJE,
        aciertos: coincidenciaTotal, // Este es el valor de "cuántas veces aparece el mismo valor de respuesta correcta"
        total: estudiantesData.length,
        porcentaje: estudiantesData.length > 0 ? (coincidenciaTotal / estudiantesData.length) * 100 : 0,
        respuestaCorrecta: correctaEsperada,
        distribucion: distribution
      });
    }
  });

  // Ordenar numéricamente por ID de pregunta
  stats.sort((a, b) => {
    const na = parseInt(a.pregunta);
    const nb = parseInt(b.pregunta);
    return (!isNaN(na) && !isNaN(nb)) ? na - nb : a.pregunta.localeCompare(b.pregunta);
  });

  // 4. Detalle por Estudiante
  const students: StudentAnswerDetail[] = estudiantesData.map(row => {
    const getField = (names: string[]) => {
      const k = Object.keys(row).find(key => names.some(n => key.toLowerCase().includes(n)));
      return k ? String(row[k]) : '';
    };

    const studentAnswers: Record<string, string> = {};
    let countCorrect = 0;

    stats.forEach(stat => {
      const originalCol = processedQuestionsMap.get(stat.pregunta);
      if (originalCol) {
        const studentVal = extremeNormalize(row[originalCol]);
        studentAnswers[stat.pregunta] = studentVal;
        if (stat.respuestaCorrecta !== '' && studentVal === stat.respuestaCorrecta) {
          countCorrect++;
        }
      }
    });

    return {
      nombre: getField(['nombre', 'estudiante', 'alumno']) || 'Estudiante Sin Nombre',
      grupo: getField(['grupo', 'grado', 'curso', 'seccion']) || '-',
      respuestas: studentAnswers,
      aciertos: countCorrect
    };
  });

  const leng = stats.filter(s => s.materia === Subject.LENGUAJE);
  const math = stats.filter(s => s.materia === Subject.MATEMATICAS);

  return {
    stats,
    students,
    totalStudents: estudiantesData.length,
    avgLenguaje: leng.length > 0 ? leng.reduce((a, b) => a + b.porcentaje, 0) / leng.length : 0,
    avgMatematicas: math.length > 0 ? math.reduce((a, b) => a + b.porcentaje, 0) / math.length : 0,
    detectedColumns: studentHeaders
  };
};

