import * as XLSX from 'xlsx';
import { AnswerKey, Subject, ProcessedResults, QuestionStats, OptionBreakdown, StudentAnswerDetail } from '../types';

/**
 * Normalización para IDs y Respuestas:
 * - Convierte a string, quita espacios y pone en mayúsculas.
 * - Maneja el formato ".0" de Excel para números.
 * - Limpia caracteres especiales para dejar solo la letra o el número base.
 */
const normalizeValue = (val: any): string => {
  if (val === null || val === undefined) return '';
  let str = String(val).trim().toUpperCase();
  if (str.endsWith('.0')) str = str.substring(0, str.length - 2);

  // Si es una respuesta (A, B, C, D), extraemos solo la letra
  if (/^[A-D](\.|\)|$)/.test(str)) {
    return str.charAt(0);
  }

  // Si es un ID de pregunta, extraemos solo los dígitos
  const onlyDigits = str.match(/\d+/);
  if (onlyDigits) return parseInt(onlyDigits[0], 10).toString();

  return str;
};

export const parseExcelFile = async (file: File): Promise<any[]> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = new Uint8Array(e.target?.result as ArrayBuffer);
        const workbook = XLSX.read(data, { type: 'array' });
        const sheetName = workbook.SheetNames[0];
        const worksheet = workbook.Sheets[sheetName];
        const rawJson: any[] = XLSX.utils.sheet_to_json(worksheet, { 
          defval: "",
          blankrows: false 
        });
        resolve(rawJson);
      } catch (err) {
        reject(err);
      }
    };
    reader.onerror = (err) => reject(err);
    reader.readAsArrayBuffer(file);
  });
};

export const processAcademicData = (
  estudiantesData: any[],
  respuestasData: any[]
): ProcessedResults => {
  if (estudiantesData.length === 0) throw new Error("Archivo de Estudiantes sin datos.");

  // 1. Obtener encabezados de Estudiantes
  const headersEstudiantes = Object.keys(estudiantesData[0]);

  // 2. Crear mapa de la Clave de Respuestas (ID -> {Correcta, Area})
  const claveMap = new Map<string, { correcta: string; area: string }>();
  respuestasData.forEach(row => {
    const findField = (keys: string[]) => {
      const foundKey = Object.keys(row).find(rk => keys.some(k => rk.toLowerCase().includes(k.toLowerCase())));
      return foundKey ? row[foundKey] : null;
    };

    const idPregunta = normalizeValue(findField(['pregunta id', 'id', 'item']));
    const respuestaCorrecta = normalizeValue(findField(['respuesta correcta', 'correcta', 'clave']));
    const area = String(findField(['área', 'area', 'materia']) || '');

    if (idPregunta && respuestaCorrecta) {
      claveMap.set(idPregunta, { correcta: respuestaCorrecta, area });
    }
  });

  // 3. SEGUIR EL FLUJO: 
  // Buscar columnas de ID en Estudiantes -> Buscar en Clave -> Almacenar Correcta -> Contar Coincidencias
  const stats: QuestionStats[] = [];
  const questionColumnsMapping = new Map<string, string>(); // ID -> Nombre de columna real

  headersEstudiantes.forEach(header => {
    const idNormalizado = normalizeValue(header);
    // Verificamos si este ID de columna existe en nuestra clave de respuestas
    if (claveMap.has(idNormalizado)) {
      questionColumnsMapping.set(idNormalizado, header);

      const infoClave = claveMap.get(idNormalizado)!;
      let countAciertos = 0;
      const distribucion: OptionBreakdown = { A: 0, B: 0, C: 0, D: 0, otros: 0 };

      // Regresar a la columna de estudiantes y contar
      estudiantesData.forEach(estudiante => {
        const respuestaAlumno = normalizeValue(estudiante[header]);

        // Conteo para distribución visual
        if (['A', 'B', 'C', 'D'].includes(respuestaAlumno)) {
          distribucion[respuestaAlumno as keyof OptionBreakdown]++;
        } else if (respuestaAlumno !== '') {
          distribucion.otros++;
        }

        // EL CONTEO DE COINCIDENCIAS
        if (respuestaAlumno === infoClave.correcta && infoClave.correcta !== '') {
          countAciertos++;
        }
      });

      stats.push({
        pregunta: idNormalizado,
        materia: infoClave.area.toLowerCase().includes('mat') ? Subject.MATEMATICAS : Subject.LENGUAJE,
        aciertos: countAciertos,
        total: estudiantesData.length,
        porcentaje: estudiantesData.length > 0 ? (countAciertos / estudiantesData.length) * 100 : 0,
        respuestaCorrecta: infoClave.correcta,
        distribucion
      });
    }
  });

  // Ordenar los resultados por número de pregunta
  stats.sort((a, b) => parseInt(a.pregunta) - parseInt(b.pregunta));

  // 4. Detalle de Estudiantes (Auditoría)
  const students: StudentAnswerDetail[] = estudiantesData.map(row => {
    const findInfo = (keys: string[]) => {
      const keyFound = Object.keys(row).find(k => keys.some(target => k.toLowerCase().includes(target)));
      return keyFound ? String(row[keyFound]) : '';
    };

    const studentAnswers: Record<string, string> = {};
    let totalAciertosEstudiante = 0;

    stats.forEach(stat => {
      const colOriginal = questionColumnsMapping.get(stat.pregunta);
      if (colOriginal) {
        const r = normalizeValue(row[colOriginal]);
        studentAnswers[stat.pregunta] = r;
        if (r === stat.respuestaCorrecta && r !== '') {
          totalAciertosEstudiante++;
        }
      }
    });

    return {
      nombre: findInfo(['nombre', 'estudiante', 'alumno']),
      grupo: findInfo(['grupo', 'grado', 'sección']),
      respuestas: studentAnswers,
      aciertos: totalAciertosEstudiante
    };
  });

  const lengStats = stats.filter(s => s.materia === Subject.LENGUAJE);
  const mathStats = stats.filter(s => s.materia === Subject.MATEMATICAS);

  return {
    stats,
    students,
    totalStudents: estudiantesData.length,
    avgLenguaje: lengStats.length > 0 ? lengStats.reduce((a, b) => a + b.porcentaje, 0) / lengStats.length : 0,
    avgMatematicas: mathStats.length > 0 ? mathStats.reduce((a, b) => a + b.porcentaje, 0) / mathStats.length : 0,
    detectedColumns: headersEstudiantes
  };
};

export const downloadResultsAsExcel = (results: QuestionStats[]) => {
  const data = results.map((s, idx) => ({
    'Ítem': idx + 1,
    'Número de Pregunta': s.pregunta,
    'Materia': s.materia,
    'Respuesta Correcta (Clave)': s.respuestaCorrecta,
    'CONTEO DE ACIERTOS': s.aciertos,
    'Total Estudiantes': s.total,
    '% de Logro': `${s.porcentaje.toFixed(1)}%`
  }));

  const worksheet = XLSX.utils.json_to_sheet(data);
  const workbook = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(workbook, worksheet, "Resultados_Auditoria");
  XLSX.writeFile(workbook, "EduAnalytica_Reporte_Aciertos.xlsx");
};

