import * as XLSX from 'xlsx';
import { AnswerKey, Subject, ProcessedResults, QuestionStats, OptionBreakdown, StudentAnswerDetail } from '../types';

/**
 * Normalización avanzada:
 * - Si es 'NR', devuelve null para ser ignorado.
 * - Limpia formatos de Excel (.0) y espacios.
 * - Extrae solo la letra (A-D) o el número base (ID).
 */
const normalizeValue = (val: any): string | null => {
  if (val === null || val === undefined) return '';
  let str = String(val).trim().toUpperCase();

  if (str === 'NR' || str === 'N/R' || str === 'N.R') return null;

  if (str.endsWith('.0')) str = str.substring(0, str.length - 2);

  // Extraer letra si es respuesta
  if (/^[A-D](\.|\)|$)/.test(str)) return str.charAt(0);

  // Extraer número si es ID
  const onlyDigits = str.match(/\d+/);
  if (onlyDigits) return parseInt(onlyDigits[0], 10).toString();

  return str;
};

export const parseExcelFile = async (file: File): Promise<any[]> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = new Uint8Array(e.target?.result as ArrayBuffer);
        const workbook = XLSX.read(data, { type: 'array' });
        const worksheet = workbook.Sheets[workbook.SheetNames[0]];
        const rawJson: any[] = XLSX.utils.sheet_to_json(worksheet, { 
          defval: "",
          blankrows: false 
        });
        resolve(rawJson);
      } catch (err) {
        reject(err);
      }
    };
    reader.onerror = (err) => reject(err);
    reader.readAsArrayBuffer(file);
  });
};

export const processAcademicData = (
  estudiantesData: any[],
  respuestasData: any[]
): ProcessedResults => {
  if (estudiantesData.length === 0) throw new Error("Archivo de Estudiantes sin registros.");

  const headersEstudiantes = Object.keys(estudiantesData[0]);

  // 1. Mapear Clave de Respuestas (ID -> {Correcta, Materia})
  const claveMap = new Map<string, { correcta: string; materia: Subject }>();
  respuestasData.forEach(row => {
    const find = (keys: string[]) => {
      const k = Object.keys(row).find(rk => keys.some(target => rk.toLowerCase().includes(target)));
      return k ? row[k] : null;
    };

    const id = normalizeValue(find(['pregunta id', 'id', 'item']));
    const correcta = normalizeValue(find(['respuesta correcta', 'correcta', 'clave']));
    const area = String(find(['área', 'area', 'materia', 'asignatura']) || '').toLowerCase();

    if (id && correcta) {
      claveMap.set(id, {
        correcta,
        materia: (area.includes('mat') || area.includes('calc')) ? Subject.MATEMATICAS : Subject.LENGUAJE
      });
    }
  });

  // 2. Procesar Columnas de Estudiantes
  const stats: QuestionStats[] = [];
  const colMapping = new Map<string, string>();

  headersEstudiantes.forEach(header => {
    const idNorm = normalizeValue(header);
    if (idNorm && claveMap.has(idNorm)) {
      colMapping.set(idNorm, header);
      const info = claveMap.get(idNorm)!;

      let aciertos = 0;
      let evaluadosRealmente = 0;
      const dist: OptionBreakdown = { A: 0, B: 0, C: 0, D: 0, otros: 0 };

      estudiantesData.forEach(student => {
        const valRaw = student[header];
        const valClean = normalizeValue(valRaw);

        // Si es NR (null), no lo evaluamos ni lo contamos para el porcentaje
        if (valClean === null) return;

        evaluadosRealmente++;

        if (['A', 'B', 'C', 'D'].includes(valClean)) {
          dist[valClean as keyof OptionBreakdown]++;
        } else if (valClean !== '') {
          dist.otros++;
        }

        if (valClean === info.correcta && info.correcta !== '') {
          aciertos++;
        }
      });

      stats.push({
        pregunta: idNorm,
        materia: info.materia,
        aciertos,
        total: evaluadosRealmente, // Solo los que no son NR
        porcentaje: evaluadosRealmente > 0 ? (aciertos / evaluadosRealmente) * 100 : 0,
        respuestaCorrecta: info.correcta,
        distribucion: dist
      });
    }
  });

  // Ordenar por ID numérico
  stats.sort((a, b) => parseInt(a.pregunta) - parseInt(b.pregunta));

  // 3. Auditoría por Estudiante
  const students: StudentAnswerDetail[] = estudiantesData.map(row => {
    const findVal = (keys: string[]) => {
      const k = Object.keys(row).find(key => keys.some(t => key.toLowerCase().includes(t)));
      return k ? String(row[k]) : '';
    };

    const studentAnswers: Record<string, string> = {};
    let score = 0;

    stats.forEach(s => {
      const col = colMapping.get(s.pregunta);
      if (col) {
        const ans = normalizeValue(row[col]);
        studentAnswers[s.pregunta] = ans === null ? 'NR' : ans;
        if (ans === s.respuestaCorrecta && ans !== null && ans !== '') {
          score++;
        }
      }
    });

    return {
      nombre: findVal(['nombre', 'estudiante', 'alumno']),
      grupo: findVal(['grupo', 'grado', 'sección']),
      respuestas: studentAnswers,
      aciertos: score
    };
  });

  const leng = stats.filter(s => s.materia === Subject.LENGUAJE);
  const math = stats.filter(s => s.materia === Subject.MATEMATICAS);

  return {
    stats,
    students,
    totalStudents: estudiantesData.length,
    avgLenguaje: leng.length ? leng.reduce((a, b) => a + b.porcentaje, 0) / leng.length : 0,
    avgMatematicas: math.length ? math.reduce((a, b) => a + b.porcentaje, 0) / math.length : 0,
    detectedColumns: headersEstudiantes
  };
};

export const downloadResultsAsExcel = (results: QuestionStats[]) => {
  const data = results.map((s, idx) => ({
    'Ítem': idx + 1,
    'Pregunta ID': s.pregunta,
    'Materia': s.materia,
    'Clave': s.respuestaCorrecta,
    'ACIERTOS': s.aciertos,
    'Total Válidos (Sin NR)': s.total,
    '% Logro': `${s.porcentaje.toFixed(1)}%`
  }));

  const ws = XLSX.utils.json_to_sheet(data);
  const wb = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb, ws, "Auditoria");
  XLSX.writeFile(wb, "Reporte_EduAnalytica_Final.xlsx");
};

