const App: React.FC = () => {
  const [estudiantesFile, setEstudiantesFile] = useState<File | null>(null);
  const [respuestasFile, setRespuestasFile] = useState<File | null>(null);
  const [loading, setLoading] = useState(false);
  const [results, setResults] = useState<ProcessedResults | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleProcess = useCallback(async () => {
    if (!estudiantesFile || !respuestasFile) {
      setError("Por favor, sube ambos archivos para continuar.");
      return;
    }

    setLoading(true);
    setError(null);

    try {
      /**
       * ESPECIFICACIÓN:
       * - Estudiantes: IDs en Fila 2, Datos en Fila 3 -> range: 1
       * - Respuestas: IDs en Fila 2 (Col B), Clave en Fila 2 (Col G) -> range: 1
       */
      const [estudiantesData, respuestasData] = await Promise.all([
        parseExcelFile(estudiantesFile, 1), 
        parseExcelFile(respuestasFile, 1)
      ]);

      if (estudiantesData.length === 0 || respuestasData.length === 0) {
        throw new Error("Uno de los archivos parece no tener datos válidos a partir de la fila especificada.");
      }

      const processed = processAcademicData(estudiantesData, respuestasData);
      setResults(processed);
    } catch (err: any) {
      console.error(err);
      setError(`Error: ${err.message || "Asegúrate de que los archivos tengan el formato correcto (Fila 2 encabezados)."}`);
    } finally {
      setLoading(false);
    }
  }, [estudiantesFile, respuestasFile]);

