              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <FileUpload 
                  label="1. Estudiantes" 
                  description="Fila 2 (IDs) | Fila 3 (Datos)"
                  accept=".xlsx, .xls, .csv"
                  onFileSelect={setEstudiantesFile}
                  selectedFileName={estudiantesFile?.name}
                />
                <FileUpload 
                  label="2. Respuestas" 
                  description="Fila 2: Col B (ID) y Col G (Clave)"
                  accept=".xlsx, .xls, .csv"
                  onFileSelect={setRespuestasFile}
                  selectedFileName={respuestasFile?.name}
                />
