import * as XLSX from 'xlsx';
import { Subject, QuestionStats, OptionBreakdown, StudentAnswerDetail } from '../types';

// Tipos internos para la simulación de tablas
interface EstudianteRow {
  grupo: string;
  nombre: string;
  respuestas: Record<string, string>;
}

interface RespuestaClaveRow {
  orden: number;
  preguntaId: string;
  area: string;
  competencia: string;
  afirmacion: string;
  evidencia: string;
  correcta: string;
}

const normalize = (val: any): string => {
  if (val === null || val === undefined) return "";
  return String(val).trim().toUpperCase();
};

const extractNumber = (val: any): string => {
  const str = normalize(val);
  const match = str.match(/\d+/);
  return match ? parseInt(match[0], 10).toString() : str;
};

export const parseExcelFile = async (file: File, range: number = 0): Promise<any[]> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = new Uint8Array(e.target?.result as ArrayBuffer);
        const workbook = XLSX.read(data, { type: 'array' });
        const worksheet = workbook.Sheets[workbook.SheetNames[0]];
        const rawJson: any[] = XLSX.utils.sheet_to_json(worksheet, { 
          defval: "",
          blankrows: false,
          range: range
        });
        resolve(rawJson);
      } catch (err) {
        reject(err);
      }
    };
    reader.onerror = (err) => reject(err);
    reader.readAsArrayBuffer(file);
  });
};

export const processAcademicData = (
  estudiantesRaw: any[],
  respuestasRaw: any[]
) => {
  // 1. SIMULACIÓN DE TABLA: RespuestasClave (Col B: ID, Col G: Correcta)
  const tablaRespuestas: RespuestaClaveRow[] = respuestasRaw.map((row, index) => {
    const keys = Object.keys(row);
    return {
      orden: index + 1,
      preguntaId: extractNumber(row[keys[1]]), // Columna B
      area: normalize(row[keys[2]]),
      competencia: normalize(row[keys[3]]),
      afirmacion: normalize(row[keys[4]]),
      evidencia: normalize(row[keys[5]]),
      correcta: normalize(row[keys[6]]) // Columna G
    };
  }).filter(r => r.preguntaId !== "" && r.correcta !== "");

  // 2. SIMULACIÓN DE TABLA: Estudiantes (Headers Fila 2)
  const headers = Object.keys(estudiantesRaw[0]);
  const tablaEstudiantes: EstudianteRow[] = estudiantesRaw.map(row => {
    const findValue = (keywords: string[]) => {
      const k = headers.find(h => keywords.some(key => h.toLowerCase().includes(key)));
      return k ? normalize(row[k]) : "";
    };

    const respuestasAlumno: Record<string, string> = {};
    // Mapeamos las 40 columnas de preguntas basándonos en los IDs de la tablaRespuestas
    tablaRespuestas.forEach(r => {
      const colHeader = headers.find(h => extractNumber(h) === r.preguntaId);
      if (colHeader) {
        respuestasAlumno[r.preguntaId] = normalize(row[colHeader]);
      }
    });

    return {
      grupo: findValue(['grupo', 'grado']),
      nombre: findValue(['nombre', 'estudiante', 'alumno']),
      respuestas: respuestasAlumno
    };
  }).filter(e => e.nombre !== "");

  // 3. PROCESAMIENTO DE RESULTADOS (Agregación SQL-Like)
  // Generamos la lista solicitada: Orden, Pregunta ID, Conteo de Aciertos
  const resultadosFinales = tablaRespuestas.map(r => {
    let conteoCorrectas = 0;
    const dist: OptionBreakdown = { A: 0, B: 0, C: 0, D: 0, otros: 0 };

    tablaEstudiantes.forEach(est => {
      const respAlumno = est.respuestas[r.preguntaId];
      if (respAlumno === r.correcta) {
        conteoCorrectas++;
      }

      if (['A', 'B', 'C', 'D'].includes(respAlumno)) {
        dist[respAlumno as keyof OptionBreakdown]++;
      } else if (respAlumno !== "" && respAlumno !== "NR") {
        dist.otros++;
      }
    });

    return {
      orden: r.orden,
      preguntaId: r.preguntaId,
      correcta: r.correcta,
      aciertos: conteoCorrectas,
      totalParticipantes: tablaEstudiantes.length,
      porcentaje: (conteoCorrectas / tablaEstudiantes.length) * 100,
      area: r.area,
      distribucion: dist
    };
  });

  return {
    resultadosFinales,
    totalEstudiantes: tablaEstudiantes.length,
    stats: resultadosFinales.map(r => ({
      pregunta: r.preguntaId,
      materia: (r.area.includes('MAT') || r.area.includes('NUM')) ? Subject.MATEMATICAS : Subject.LENGUAJE,
      aciertos: r.aciertos,
      total: r.totalParticipantes,
      porcentaje: r.porcentaje,
      respuestaCorrecta: r.correcta,
      distribucion: r.distribucion
    })),
    estudiantesAudit: tablaEstudiantes.map(e => ({
      nombre: e.nombre,
      grupo: e.grupo,
      respuestas: e.respuestas,
      aciertos: tablaRespuestas.reduce((acc, r) => acc + (e.respuestas[r.preguntaId] === r.correcta ? 1 : 0), 0)
    }))
  };
};

export const downloadResultsAsExcel = (results: any[]) => {
  const data = results.map(r => ({
    'Item': r.orden,
    'Pregunta ID': r.preguntaId,
    'Clave': r.correcta,
    'Cantidad Aciertos': r.aciertos,
    'Total Estudiantes': r.totalParticipantes,
    '% Logro': `${r.porcentaje.toFixed(1)}%`,
    'Área': r.area
  }));

  const ws = XLSX.utils.json_to_sheet(data);
  const wb = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb, ws, "Resultados");
  XLSX.writeFile(wb, "Reporte_Aciertos_SQLite_Arch.xlsx");
};

