): ProcessedResults => {
  if (estudiantesData.length === 0) throw new Error("Archivo de Estudiantes sin registros.");

  const claveMap = new Map<string, { correcta: string; materia: Subject }>();

  respuestasData.forEach(row => {
    const keys = Object.keys(row);

    const findByHeader = (keywords: string[]) => {
      const k = keys.find(rk => keywords.some(target => rk.toLowerCase().includes(target)));
      return k ? row[k] : null;
    };

    // Priorizamos Columna B (index 1) y G (index 6) según requerimiento
    const idValRaw = findByHeader(['pregunta id', 'id', 'item']) || row[keys[1]];
    const correctaValRaw = findByHeader(['respuesta correcta', 'correcta', 'clave']) || row[keys[6]];
    const areaValRaw = String(findByHeader(['área', 'area', 'materia', 'asignatura']) || row[keys[4]] || '').toLowerCase();

    const id = normalizeValue(idValRaw);
    const correcta = normalizeValue(correctaValRaw);

    if (id && correcta) {
      const isMath = areaValRaw.includes('mat') || areaValRaw.includes('calc') || areaValRaw.includes('num');
      claveMap.set(id, {
        correcta,
        materia: isMath ? Subject.MATEMATICAS : Subject.LENGUAJE
      });
    }
  });

  const headersEstudiantes = Object.keys(estudiantesData[0]);
  const questionCols: { id: string, header: string }[] = [];
  headersEstudiantes.forEach(header => {
    const idNorm = normalizeValue(header);
    if (idNorm && claveMap.has(idNorm)) {
      questionCols.push({ id: idNorm, header });
    }
  });

  const studentsWithName = estudiantesData.filter(row => {
    const findVal = (keys: string[]) => {
      const k = Object.keys(row).find(key => keys.some(t => key.toLowerCase().includes(t)));
      return k ? String(row[k]).trim() : '';
    };
    return findVal(['nombre', 'estudiante', 'alumno']) !== '';
  });

  // Muestra estadística: alumnos sin NR para asegurar porcentajes limpios
  const studentsForStats = studentsWithName.filter(student => {
    return questionCols.every(q => normalizeValue(student[q.header]) !== null);
  });

  const stats: QuestionStats[] = questionCols.map(q => {
    const info = claveMap.get(q.id)!;
    let aciertos = 0;
    const dist: OptionBreakdown = { A: 0, B: 0, C: 0, D: 0, otros: 0 };

    studentsForStats.forEach(student => {
      const valClean = normalizeValue(student[q.header]);
      if (valClean === null) return; 

      if (['A', 'B', 'C', 'D'].includes(valClean)) {
        dist[valClean as keyof OptionBreakdown]++;
      } else if (valClean !== '') {
        dist.otros++;
      }

      if (valClean === info.correcta && info.correcta !== '') {
        aciertos++;
      }
    });

    return {
      pregunta: q.id,
      materia: info.materia,
      aciertos,
      total: studentsForStats.length,
      porcentaje: studentsForStats.length > 0 ? (aciertos / studentsForStats.length) * 100 : 0,
      respuestaCorrecta: info.correcta,
      distribucion: dist
    };
  });

  stats.sort((a, b) => {
    const na = parseInt(a.pregunta);
    const nb = parseInt(b.pregunta);
    if (!isNaN(na) && !isNaN(nb)) return na - nb;
    return a.pregunta.localeCompare(b.pregunta);
  });

  const studentsDetails: StudentAnswerDetail[] = studentsWithName.map(row => {
    const findVal = (keys: string[]) => {
      const k = Object.keys(row).find(key => keys.some(t => key.toLowerCase().includes(t)));
      return k ? String(row[k]) : '';
    };

    const studentAnswers: Record<string, string> = {};
    let score = 0;

    stats.forEach(s => {
      const qCol = questionCols.find(qc => qc.id === s.pregunta);
      if (qCol) {
        const ans = normalizeValue(row[qCol.header]);
        studentAnswers[s.pregunta] = ans === null ? 'NR' : ans;
        if (ans === s.respuestaCorrecta && ans !== null && ans !== '') {
          score++;
        }
      }
    });

    return {
      nombre: findVal(['nombre', 'estudiante', 'alumno']),
      grupo: findVal(['grupo', 'grado', 'sección']),
      respuestas: studentAnswers,
      aciertos: score
    };
  });

  const leng = stats.filter(s => s.materia === Subject.LENGUAJE);
  const math = stats.filter(s => s.materia === Subject.MATEMATICAS);

  return {
    stats,
    students: studentsDetails,
    totalStudents: studentsWithName.length,
    avgLenguaje: leng.length ? leng.reduce((a, b) => a + b.porcentaje, 0) / leng.length : 0,
    avgMatematicas: math.length ? math.reduce((a, b) => a + b.porcentaje, 0) / math.length : 0,
    detectedColumns: headersEstudiantes
  };
};

export const downloadResultsAsExcel = (results: QuestionStats[]) => {
  const data = results.map((s, idx) => ({
    'Ítem': idx + 1,
    'Pregunta ID': s.pregunta,
    'Materia': s.materia,
    'Clave': s.respuestaCorrecta,
    'ACIERTOS': s.aciertos,
    'Muestra Válida': s.total,
    '% Logro': `${s.porcentaje.toFixed(1)}%`
  }));

  const ws = XLSX.utils.json_to_sheet(data);
  const wb = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb, ws, "Auditoria");
  XLSX.writeFile(wb, "Reporte_EduAnalytica.xlsx");
};

