import * as XLSX from 'xlsx';
import { Subject, QuestionStats, OptionBreakdown, StudentAnswerDetail, ProcessedResults } from '../types';

/**
 * Normalización simple para asegurar el match entre los encabezados de Estudiantes
 * y los IDs en el archivo de Respuestas.
 */
const normalizeValue = (val: any): string | null => {
  if (val === null || val === undefined) return '';
  let str = String(val).trim().toUpperCase();

  if (str === 'NR' || str === 'N/R' || str === 'N.R') return null;

  // Limpiar formatos de decimales de Excel (.0)
  if (str.endsWith('.0')) str = str.substring(0, str.length - 2);

  // Para respuestas (A, B, C, D)
  if (/^[A-D](\.|\)|$)/.test(str)) return str.charAt(0);

  // Extraer el número base para IDs de preguntas
  const onlyDigits = str.match(/\d+/);
  if (onlyDigits) return parseInt(onlyDigits[0], 10).toString();

  return str;
};

export const parseExcelFile = async (file: File, range: number = 0): Promise<any[]> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = new Uint8Array(e.target?.result as ArrayBuffer);
        const workbook = XLSX.read(data, { type: 'array' });
        const worksheet = workbook.Sheets[workbook.SheetNames[0]];

        const rawJson: any[] = XLSX.utils.sheet_to_json(worksheet, { 
          defval: "",
          blankrows: false,
          range: range // 0 para leer desde la primera fila
        });
        resolve(rawJson);
      } catch (err) {
        reject(err);
      }
    };
    reader.onerror = (err) => reject(err);
    reader.readAsArrayBuffer(file);
  });
};

export const processAcademicData = (
  estudiantesData: any[],
  respuestasData: any[]
): ProcessedResults => {
  if (estudiantesData.length === 0) throw new Error("El archivo de Estudiantes está vacío.");

  const claveMap = new Map<string, { correcta: string; materia: Subject }>();

  // Procesar Clave de Respuestas
  respuestasData.forEach(row => {
    const findByKeywords = (keywords: string[]) => {
      const k = Object.keys(row).find(key => keywords.some(t => key.toLowerCase().includes(t)));
      return k ? row[k] : null;
    };

    const id = normalizeValue(findByKeywords(['id', 'pregunta', 'item']));
    const correcta = normalizeValue(findByKeywords(['correcta', 'clave', 'respuesta']));
    const area = String(findByKeywords(['área', 'materia', 'asignatura']) || '').toLowerCase();

    if (id && correcta) {
      const isMath = area.includes('mat') || area.includes('calc') || area.includes('num');
      claveMap.set(id, {
        correcta,
        materia: isMath ? Subject.MATEMATICAS : Subject.LENGUAJE
      });
    }
  });

  const headersEstudiantes = Object.keys(estudiantesData[0]);
  const questionCols: { id: string, header: string }[] = [];

  // Detectar qué columnas en estudiantes son preguntas válidas
  headersEstudiantes.forEach(header => {
    const idNorm = normalizeValue(header);
    if (idNorm && claveMap.has(idNorm)) {
      questionCols.push({ id: idNorm, header });
    }
  });

  // Filtrar alumnos con nombre
  const studentsWithName = estudiantesData.filter(row => {
    const nameKey = Object.keys(row).find(k => ['nombre', 'estudiante', 'alumno'].some(t => k.toLowerCase().includes(t)));
    return nameKey && String(row[nameKey]).trim() !== '';
  });

  // Muestra estadística: Alumnos que respondieron todo (sin NR) para porcentajes precisos
  const studentsForStats = studentsWithName.filter(student => {
    return questionCols.every(q => normalizeValue(student[q.header]) !== null);
  });

  const stats: QuestionStats[] = questionCols.map(q => {
    const info = claveMap.get(q.id)!;
    let aciertos = 0;
    const dist: OptionBreakdown = { A: 0, B: 0, C: 0, D: 0, otros: 0 };

    studentsForStats.forEach(student => {
      const valClean = normalizeValue(student[q.header]);
      if (valClean === null) return; 

      if (['A', 'B', 'C', 'D'].includes(valClean)) {
        dist[valClean as keyof OptionBreakdown]++;
      } else if (valClean !== '') {
        dist.otros++;
      }

      if (valClean === info.correcta) {
        aciertos++;
      }
    });

    return {
      pregunta: q.id,
      materia: info.materia,
      aciertos,
      total: studentsForStats.length,
      porcentaje: studentsForStats.length > 0 ? (aciertos / studentsForStats.length) * 100 : 0,
      respuestaCorrecta: info.correcta,
      distribucion: dist
    };
  });

  // Ordenar preguntas por ID numérico
  stats.sort((a, b) => parseInt(a.pregunta) - parseInt(b.pregunta));

  // Generar detalle por estudiante
  const studentsDetails: StudentAnswerDetail[] = studentsWithName.map(row => {
    const findVal = (keywords: string[]) => {
      const k = Object.keys(row).find(key => keywords.some(t => key.toLowerCase().includes(t)));
      return k ? String(row[k]) : '';
    };

    const studentAnswers: Record<string, string> = {};
    let score = 0;

    stats.forEach(s => {
      const qCol = questionCols.find(qc => qc.id === s.pregunta);
      if (qCol) {
        const ans = normalizeValue(row[qCol.header]);
        studentAnswers[s.pregunta] = ans === null ? 'NR' : ans;
        if (ans === s.respuestaCorrecta && ans !== null) {
          score++;
        }
      }
    });

    return {
      nombre: findVal(['nombre', 'estudiante', 'alumno']),
      grupo: findVal(['grupo', 'grado', 'sección']),
      respuestas: studentAnswers,
      aciertos: score
    };
  });

  const leng = stats.filter(s => s.materia === Subject.LENGUAJE);
  const math = stats.filter(s => s.materia === Subject.MATEMATICAS);

  return {
    stats,
    students: studentsDetails,
    totalStudents: studentsWithName.length,
    avgLenguaje: leng.length ? leng.reduce((a, b) => a + b.porcentaje, 0) / leng.length : 0,
    avgMatematicas: math.length ? math.reduce((a, b) => a + b.porcentaje, 0) / math.length : 0,
    detectedColumns: headersEstudiantes
  };
};

