/**
 * Normalización para asegurar el match exacto entre archivos.
 */
const normalizeValue = (val: any): string | null => {
  if (val === null || val === undefined) return '';
  let str = String(val).trim().toUpperCase();

  if (str === 'NR' || str === 'N/R' || str === 'N.R') return null;

  if (str.endsWith('.0')) str = str.substring(0, str.length - 2);

  if (/^[A-D](\.|\)|$)/.test(str)) return str.charAt(0);

  const onlyDigits = str.match(/\d+/);
  if (onlyDigits) return parseInt(onlyDigits[0], 10).toString();

  return str;
};

export const parseExcelFile = async (file: File, range: number = 0): Promise<any[]> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = new Uint8Array(e.target?.result as ArrayBuffer);
        const workbook = XLSX.read(data, { type: 'array' });
        const worksheet = workbook.Sheets[workbook.SheetNames[0]];

        const rawJson: any[] = XLSX.utils.sheet_to_json(worksheet, { 
          defval: "",
          blankrows: false,
          range: range 
        });
        resolve(rawJson);
      } catch (err) {
        reject(err);
      }
    };
    reader.onerror = (err) => reject(err);
    reader.readAsArrayBuffer(file);
  });
};

export const processAcademicData = (
  estudiantesData: any[],
  respuestasData: any[]
): any => {
  if (estudiantesData.length === 0) throw new Error("Archivo de Estudiantes sin registros.");

  // 1. Mapear Clave de Respuestas (ID -> {Correcta, Materia})
  // Según requerimiento: Columna B (ID) y Columna G (Clave)
  const itemsClave: any[] = respuestasData.map((row, index) => {
    const keys = Object.keys(row);
    const id = normalizeValue(row[keys[1]]); // Col B
    const correcta = normalizeValue(row[keys[6]]); // Col G
    const area = String(row[keys[4]] || '').toLowerCase();

    return {
      orden: index + 1,
      id,
      correcta,
      materia: (area.includes('mat') || area.includes('num')) ? Subject.MATEMATICAS : Subject.LENGUAJE
    };
  }).filter(item => item.id !== null && item.correcta !== null);

  // 2. Procesar Estudiantes y contar aciertos por ítem
  const headersEstudiantes = Object.keys(estudiantesData[0]);

  const stats = itemsClave.map(item => {
    let aciertos = 0;
    const colHeader = headersEstudiantes.find(h => normalizeValue(h) === item.id);

    if (colHeader) {
      estudiantesData.forEach(est => {
        const respAlumno = normalizeValue(est[colHeader]);
        if (respAlumno === item.correcta && respAlumno !== null) {
          aciertos++;
        }
      });
    }

    return {
      orden: item.orden,
      pregunta: item.id,
      aciertos: aciertos,
      total: estudiantesData.length,
      porcentaje: (aciertos / estudiantesData.length) * 100,
      respuestaCorrecta: item.correcta,
      materia: item.materia
    };
  });

  return {
    stats,
    totalStudents: estudiantesData.length,
    avgLenguaje: stats.filter(s => s.materia === Subject.LENGUAJE).reduce((a, b) => a + b.porcentaje, 0) / (stats.filter(s => s.materia === Subject.LENGUAJE).length || 1),
    avgMatematicas: stats.filter(s => s.materia === Subject.MATEMATICAS).reduce((a, b) => a + b.porcentaje, 0) / (stats.filter(s => s.materia === Subject.MATEMATICAS).length || 1)
  };
};

