export const processAcademicData = (
  estudiantesData: any[],
  respuestasData: any[]
): ProcessedResults => {
  if (estudiantesData.length === 0) throw new Error("Archivo de Estudiantes sin registros.");

  // 1. Mapear Clave de Respuestas
  const itemsClave = respuestasData.map((row, index) => {
    const keys = Object.keys(row);
    const id = normalizeValue(row[keys[1]]);
    const correcta = normalizeValue(row[keys[6]]);
    const area = String(row[keys[4]] || '').toLowerCase();

    return {
      orden: index + 1,
      id,
      correcta,
      materia: (area.includes('mat') || area.includes('num')) ? Subject.MATEMATICAS : Subject.LENGUAJE
    };
  }).filter(item => item.id !== null && item.correcta !== null);

  const headersEstudiantes = Object.keys(estudiantesData[0]);

  // 2. Estadísticas por Pregunta
  const stats: QuestionStats[] = itemsClave.map(item => {
    let aciertos = 0;
    const dist: OptionBreakdown = { A: 0, B: 0, C: 0, D: 0, otros: 0 };
    const colHeader = headersEstudiantes.find(h => normalizeValue(h) === item.id);

    estudiantesData.forEach(est => {
      if (!colHeader) return;
      const respAlumno = normalizeValue(est[colHeader]);

      if (respAlumno === item.correcta && respAlumno !== null) {
        aciertos++;
      }

      if (respAlumno && ['A', 'B', 'C', 'D'].includes(respAlumno)) {
        dist[respAlumno as keyof OptionBreakdown]++;
      } else if (respAlumno !== null && respAlumno !== '') {
        dist.otros++;
      }
    });

    return {
      pregunta: item.id!,
      materia: item.materia,
      aciertos,
      total: estudiantesData.length,
      porcentaje: (aciertos / estudiantesData.length) * 100,
      respuestaCorrecta: item.correcta!,
      distribucion: dist
    };
  });

  // 3. Detalle por Estudiante
  const students: StudentAnswerDetail[] = estudiantesData.map(row => {
    const findVal = (keywords: string[]) => {
      const k = Object.keys(row).find(key => keywords.some(t => key.toLowerCase().includes(t)));
      return k ? String(row[k]) : '';
    };

    const studentAnswers: Record<string, string> = {};
    let studentAciertos = 0;

    itemsClave.forEach(item => {
      const colHeader = headersEstudiantes.find(h => normalizeValue(h) === item.id);
      if (colHeader) {
        const ans = normalizeValue(row[colHeader]);
        studentAnswers[item.id!] = ans === null ? 'NR' : ans;
        if (ans === item.correcta && ans !== null) {
          studentAciertos++;
        }
      }
    });

    return {
      nombre: findVal(['nombre', 'estudiante', 'alumno']),
      grupo: findVal(['grupo', 'grado', 'sección']),
      respuestas: studentAnswers,
      aciertos: studentAciertos
    };
  }).filter(s => s.nombre !== '');

  const leng = stats.filter(s => s.materia === Subject.LENGUAJE);
  const math = stats.filter(s => s.materia === Subject.MATEMATICAS);

  return {
    stats,
    students,
    totalStudents: students.length,
    avgLenguaje: leng.length ? leng.reduce((a, b) => a + b.porcentaje, 0) / leng.length : 0,
    avgMatematicas: math.length ? math.reduce((a, b) => a + b.porcentaje, 0) / math.length : 0,
    detectedColumns: headersEstudiantes
  };
};

