import * as XLSX from 'xlsx';
import { Subject, QuestionStats, OptionBreakdown, StudentAnswerDetail, ProcessedResults } from '../types';

/**
 * Normalización para asegurar el match exacto entre archivos.
 */
const normalizeValue = (val: any): string | null => {
  if (val === null || val === undefined) return '';
  let str = String(val).trim().toUpperCase();

  if (str === 'NR' || str === 'N/R' || str === 'N.R') return null;

  if (str.endsWith('.0')) str = str.substring(0, str.length - 2);

  if (/^[A-D](\.|\)|$)/.test(str)) return str.charAt(0);

  const onlyDigits = str.match(/\d+/);
  if (onlyDigits) return parseInt(onlyDigits[0], 10).toString();

  return str;
};

export const parseExcelFile = async (file: File, range: number = 0): Promise<any[]> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = new Uint8Array(e.target?.result as ArrayBuffer);
        const workbook = XLSX.read(data, { type: 'array' });
        const worksheet = workbook.Sheets[workbook.SheetNames[0]];

        const rawJson: any[] = XLSX.utils.sheet_to_json(worksheet, { 
          defval: "",
          blankrows: false,
          range: range 
        });
        resolve(rawJson);
      } catch (err) {
        reject(err);
      }
    };
    reader.onerror = (err) => reject(err);
    reader.readAsArrayBuffer(file);
  });
};

export const processAcademicData = (
  estudiantesData: any[],
  respuestasData: any[]
): ProcessedResults => {
  if (estudiantesData.length === 0) throw new Error("Archivo de Estudiantes sin registros.");

  // 1. Mapear Clave de Respuestas (Basado en el flujo solicitado)
  // Col B (index 1) = ID, Col G (index 6) = Respuesta Correcta
  const itemsClave = respuestasData.map((row, index) => {
    const keys = Object.keys(row);
    const id = normalizeValue(row[keys[1]]);
    const correcta = normalizeValue(row[keys[6]]);
    const area = String(row[keys[2]] || row[keys[4]] || '').toLowerCase(); // Intentar detectar Area

    return {
      orden: index + 1,
      id,
      correcta,
      materia: (area.includes('mat') || area.includes('num')) ? Subject.MATEMATICAS : Subject.LENGUAJE
    };
  }).filter(item => item.id !== null && item.correcta !== null);

  const headersEstudiantes = Object.keys(estudiantesData[0]);

  // 2. Estadísticas por Pregunta (Conteo de Aciertos)
  const stats: QuestionStats[] = itemsClave.map(item => {
    let aciertos = 0;
    const dist: OptionBreakdown = { A: 0, B: 0, C: 0, D: 0, otros: 0 };
    const colHeader = headersEstudiantes.find(h => normalizeValue(h) === item.id);

    estudiantesData.forEach(est => {
      if (!colHeader) return;
      const respAlumno = normalizeValue(est[colHeader]);

      if (respAlumno === item.correcta && respAlumno !== null) {
        aciertos++;
      }

      if (respAlumno && ['A', 'B', 'C', 'D'].includes(respAlumno)) {
        dist[respAlumno as keyof OptionBreakdown]++;
      } else if (respAlumno !== null && respAlumno !== '') {
        dist.otros++;
      }
    });

    return {
      orden: item.orden,
      pregunta: item.id!,
      materia: item.materia,
      aciertos,
      total: estudiantesData.length,
      porcentaje: (aciertos / estudiantesData.length) * 100,
      respuestaCorrecta: item.correcta!,
      distribucion: dist
    };
  });

  // 3. Detalle por Estudiante para Matriz
  const students: StudentAnswerDetail[] = estudiantesData.map(row => {
    const findVal = (keywords: string[]) => {
      const k = Object.keys(row).find(key => keywords.some(t => key.toLowerCase().includes(t)));
      return k ? String(row[k]) : 'Sin nombre';
    };

    const studentAnswers: Record<string, string> = {};
    let studentAciertos = 0;

    itemsClave.forEach(item => {
      const colHeader = headersEstudiantes.find(h => normalizeValue(h) === item.id);
      if (colHeader) {
        const ans = normalizeValue(row[colHeader]);
        studentAnswers[item.id!] = ans === null ? 'NR' : ans;
        if (ans === item.correcta && ans !== null) {
          studentAciertos++;
        }
      }
    });

    return {
      nombre: findVal(['nombre', 'estudiante', 'alumno']),
      grupo: findVal(['grupo', 'grado', 'sección']),
      respuestas: studentAnswers,
      aciertos: studentAciertos
    };
  }).filter(s => s.nombre !== '');

  const leng = stats.filter(s => s.materia === Subject.LENGUAJE);
  const math = stats.filter(s => s.materia === Subject.MATEMATICAS);

  return {
    stats,
    students,
    totalStudents: students.length,
    avgLenguaje: leng.length ? leng.reduce((a, b) => a + b.porcentaje, 0) / leng.length : 0,
    avgMatematicas: math.length ? math.reduce((a, b) => a + b.porcentaje, 0) / math.length : 0,
    detectedColumns: headersEstudiantes
  };
};

export const downloadResultsAsExcel = (results: QuestionStats[]) => {
  const data = results.map(s => ({
    'Ítem/Orden': s.orden,
    'Pregunta ID': s.pregunta,
    'Materia': s.materia,
    'Clave': s.respuestaCorrecta,
    'Cantidad Aciertos': s.aciertos,
    'Total Estudiantes': s.total,
    '% Logro': `${s.porcentaje.toFixed(1)}%`
  }));

  const ws = XLSX.utils.json_to_sheet(data);
  const wb = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb, ws, "Resultados_Auditoria");
  XLSX.writeFile(wb, "Reporte_General_Aciertos.xlsx");
};

