import * as XLSX from 'xlsx';
import { Subject, QuestionStats, OptionBreakdown, StudentAnswerDetail, ProcessedResults } from '../types';

/**
 * Normalización para asegurar el match exacto entre archivos.
 * Limpia espacios, convierte a mayúsculas y quita decimales de IDs numéricos.
 */
const normalizeValue = (val: any): string | null => {
  if (val === null || val === undefined) return '';
  let str = String(val).trim().toUpperCase();

  if (str === 'NR' || str === 'N/R' || str === 'N.R') return null;

  // Limpiar formatos decimales comunes en IDs numéricos de Excel (ej: "1.0" -> "1")
  if (str.endsWith('.0')) str = str.substring(0, str.length - 2);

  // Extraer solo la letra si viene como "A. Correcta"
  if (/^[A-D](\.|\)|$)/.test(str)) return str.charAt(0);

  // Si es puramente un número, lo mantenemos como string limpio
  const onlyDigits = str.match(/\d+/);
  if (onlyDigits && onlyDigits[0] === str) return str;

  return str;
};

export const parseExcelFile = async (file: File, range: number = 0): Promise<any[]> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = new Uint8Array(e.target?.result as ArrayBuffer);
        const workbook = XLSX.read(data, { type: 'array' });
        const worksheet = workbook.Sheets[workbook.SheetNames[0]];

        // Convertimos a JSON. Usamos header: 1 para obtener arrays y manejar índices físicos.
        const rawData: any[][] = XLSX.utils.sheet_to_json(worksheet, { 
          header: 1,
          defval: "",
          blankrows: false
        });

        // Si el usuario indicó un rango (fila de inicio), cortamos el array.
        // Por defecto asumimos que los datos útiles empiezan en la fila 1 (index 0).
        resolve(rawData);
      } catch (err) {
        reject(err);
      }
    };
    reader.onerror = (err) => reject(err);
    reader.readAsArrayBuffer(file);
  });
};

export const processAcademicData = (
  estudiantesRaw: any[][],
  respuestasRaw: any[][]
): ProcessedResults => {
  // Validaciones iniciales
  if (estudiantesRaw.length < 2) throw new Error("El archivo de Estudiantes debe tener al menos una fila de encabezado y una de datos.");
  if (respuestasRaw.length < 2) throw new Error("El archivo de Respuestas debe tener al menos una fila de encabezado y una de datos.");

  // En 'respuestasRaw', la primera fila son los encabezados.
  // Según el flujo: Col B (index 1) es ID, Col G (index 6) es Respuesta Correcta.
  // Empezamos desde index 1 para saltar el encabezado.
  const itemsClave = respuestasRaw.slice(1).map((row, index) => {
    const id = normalizeValue(row[1]);
    const correcta = normalizeValue(row[6]);
    const areaRaw = String(row[2] || '').toLowerCase(); // Col C es Área

    return {
      orden: index + 1,
      id,
      correcta,
      materia: (areaRaw.includes('mat') || areaRaw.includes('num')) ? Subject.MATEMATICAS : Subject.LENGUAJE
    };
  }).filter(item => item.id !== null && item.id !== "" && item.correcta !== null);

  // En 'estudiantesRaw', la primera fila (index 0) son los encabezados (Grupo, Nombre, 1, 2, 3...)
  const headersEstudiantes = estudiantesRaw[0].map(h => normalizeValue(h));
  const alumnosData = estudiantesRaw.slice(1);

  // 2. Procesar Estadísticas por Pregunta (Cruzar ID de respuestas con columnas de estudiantes)
  const stats: QuestionStats[] = itemsClave.map(item => {
    let aciertos = 0;
    const dist: OptionBreakdown = { A: 0, B: 0, C: 0, D: 0, otros: 0 };

    // Buscamos el índice físico de la columna que coincide con el ID de la pregunta
    const colIndex = headersEstudiantes.findIndex(h => h === item.id);

    if (colIndex !== -1) {
      alumnosData.forEach(row => {
        const respAlumno = normalizeValue(row[colIndex]);

        if (respAlumno === item.correcta && respAlumno !== null && respAlumno !== "") {
          aciertos++;
        }

        if (respAlumno && ['A', 'B', 'C', 'D'].includes(respAlumno)) {
          dist[respAlumno as keyof OptionBreakdown]++;
        } else if (respAlumno !== null && respAlumno !== '') {
          dist.otros++;
        }
      });
    }

    return {
      orden: item.orden,
      pregunta: item.id!,
      materia: item.materia,
      aciertos,
      total: alumnosData.length,
      porcentaje: alumnosData.length > 0 ? (aciertos / alumnosData.length) * 100 : 0,
      respuestaCorrecta: item.correcta!,
      distribucion: dist
    };
  });

  // 3. Detalle por Estudiante para la matriz completa
  const students: StudentAnswerDetail[] = alumnosData.map(row => {
    const grupo = String(row[0] || 'Sin Grupo');
    const nombre = String(row[1] || 'Sin Nombre');

    const studentAnswers: Record<string, string> = {};
    let studentAciertos = 0;

    itemsClave.forEach(item => {
      const colIndex = headersEstudiantes.findIndex(h => h === item.id);
      if (colIndex !== -1) {
        const ans = normalizeValue(row[colIndex]);
        studentAnswers[item.id!] = ans === null || ans === "" ? 'NR' : ans;
        if (ans === item.correcta && ans !== null && ans !== "") {
          studentAciertos++;
        }
      }
    });

    return {
      nombre,
      grupo,
      respuestas: studentAnswers,
      aciertos: studentAciertos
    };
  }).filter(s => s.nombre !== 'Sin Nombre' && s.nombre !== '');

  const leng = stats.filter(s => s.materia === Subject.LENGUAJE);
  const math = stats.filter(s => s.materia === Subject.MATEMATICAS);

  return {
    stats,
    students,
    totalStudents: students.length,
    avgLenguaje: leng.length ? leng.reduce((a, b) => a + b.porcentaje, 0) / leng.length : 0,
    avgMatematicas: math.length ? math.reduce((a, b) => a + b.porcentaje, 0) / math.length : 0,
    detectedColumns: headersEstudiantes.filter(h => h !== null) as string[]
  };
};

export const downloadResultsAsExcel = (results: QuestionStats[]) => {
  const data = results.map(s => ({
    'Ítem/Orden': s.orden,
    'Pregunta ID': s.pregunta,
    'Cantidad Aciertos': s.aciertos,
    'Total Estudiantes': s.total,
    '% Logro': `${s.porcentaje.toFixed(1)}%`,
    'Clave Correcta': s.respuestaCorrecta,
    'Área': s.materia
  }));

  const ws = XLSX.utils.json_to_sheet(data);
  const wb = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb, ws, "Auditoria_Aciertos");
  XLSX.writeFile(wb, "Reporte_Auditoria_Educativa.xlsx");
};

