import * as XLSX from 'xlsx';
import { Subject, QuestionStats, OptionBreakdown, StudentAnswerDetail, ProcessedResults } from '../types';

/**
 * Normalización Ultra-Robusta:
 * 1. Elimina todos los espacios en blanco (incluso los no-rompibles).
 * 2. Convierte todo a Mayúsculas.
 * 3. Si es un número (ej. 1.0), lo convierte a entero limpio (1).
 */
const normalizeValue = (val: any): string | null => {
  if (val === null || val === undefined) return null;

  // Convertir a string y limpiar espacios
  let str = String(val).replace(/\s+/g, '').toUpperCase();

  if (str === '' || str === 'NR' || str === 'N/R' || str === 'N.R' || str === 'NULL') {
    return null;
  }

  // Si es un número decimal que termina en .0 (común en Excel), lo limpiamos
  if (/^\d+\.0+$/.test(str)) {
    str = str.split('.')[0];
  }

  // Si es una respuesta con formato "A." o "A)", extraemos solo la letra
  if (/^[A-D][.)]/.test(str)) {
    return str.charAt(0);
  }

  return str;
};

export const parseExcelFile = async (file: File): Promise<any[][]> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = new Uint8Array(e.target?.result as ArrayBuffer);
        const workbook = XLSX.read(data, { type: 'array' });
        const worksheet = workbook.Sheets[workbook.SheetNames[0]];

        // Obtenemos matriz pura para control total
        const rawData: any[][] = XLSX.utils.sheet_to_json(worksheet, { 
          header: 1, 
          defval: "",
          blankrows: false
        });

        resolve(rawData);
      } catch (err) {
        reject(err);
      }
    };
    reader.onerror = (err) => reject(err);
    reader.readAsArrayBuffer(file);
  });
};

export const processAcademicData = (
  estudiantesRaw: any[][],
  respuestasRaw: any[][]
): ProcessedResults => {
  // 1. Encontrar la fila de encabezado en Respuestas (la que tenga contenido en Col B o G)
  const headerIdxResp = respuestasRaw.findIndex(row => row[1] && row[6]);
  if (headerIdxResp === -1) throw new Error("No se detectó la estructura correcta en el archivo de Respuestas.");

  const itemsClave = respuestasRaw.slice(headerIdxResp + 1).map((row, index) => {
    const id = normalizeValue(row[1]); // Col B
    const correcta = normalizeValue(row[6]); // Col G
    const areaRaw = String(row[2] || '').toLowerCase(); // Col C

    return {
      orden: index + 1,
      id,
      correcta,
      materia: (areaRaw.includes('mat') || areaRaw.includes('num')) ? Subject.MATEMATICAS : Subject.LENGUAJE
    };
  }).filter(item => item.id !== null && item.correcta !== null);

  // 2. Encontrar la fila de encabezado en Estudiantes
  // Buscamos la fila que tenga más de 5 columnas (indicativo de la fila de preguntas)
  const headerIdxEst = estudiantesRaw.findIndex(row => row.length > 5);
  if (headerIdxEst === -1) throw new Error("No se detectó la estructura de columnas en el archivo de Estudiantes.");

  const headersEstudiantes = estudiantesRaw[headerIdxEst].map(h => normalizeValue(h));
  const alumnosData = estudiantesRaw.slice(headerIdxEst + 1);

  // 3. Procesar Conteo de Aciertos
  const stats: QuestionStats[] = itemsClave.map(item => {
    let aciertos = 0;
    const dist: OptionBreakdown = { A: 0, B: 0, C: 0, D: 0, otros: 0 };

    // Encontrar el índice de la columna en Estudiantes que coincida con el ID de Respuestas
    const colIndex = headersEstudiantes.findIndex(h => h !== null && h === item.id);

    if (colIndex !== -1) {
      alumnosData.forEach(row => {
        const respAlumno = normalizeValue(row[colIndex]);

        // Comparación estricta de aciertos
        if (respAlumno !== null && respAlumno === item.correcta) {
          aciertos++;
        }

        // Distribución de opciones para gráficas
        if (respAlumno && ['A', 'B', 'C', 'D'].includes(respAlumno)) {
          dist[respAlumno as keyof OptionBreakdown]++;
        } else if (respAlumno !== null) {
          dist.otros++;
        }
      });
    }

    return {
      orden: item.orden,
      pregunta: item.id!,
      materia: item.materia,
      aciertos,
      total: alumnosData.length,
      porcentaje: alumnosData.length > 0 ? (aciertos / alumnosData.length) * 100 : 0,
      respuestaCorrecta: item.correcta!,
      distribucion: dist
    };
  });

  // 4. Detalle por Alumno
  const students: StudentAnswerDetail[] = alumnosData.map(row => {
    const grupo = String(row[0] || 'N/A').trim();
    const nombre = String(row[1] || '').trim();

    const studentAnswers: Record<string, string> = {};
    let studentAciertos = 0;

    itemsClave.forEach(item => {
      const colIndex = headersEstudiantes.findIndex(h => h === item.id);
      if (colIndex !== -1) {
        const ans = normalizeValue(row[colIndex]);
        studentAnswers[item.id!] = ans === null ? 'NR' : ans;
        if (ans !== null && ans === item.correcta) {
          studentAciertos++;
        }
      }
    });

    return {
      nombre,
      grupo,
      respuestas: studentAnswers,
      aciertos: studentAciertos
    };
  }).filter(s => s.nombre !== "");

  const leng = stats.filter(s => s.materia === Subject.LENGUAJE);
  const math = stats.filter(s => s.materia === Subject.MATEMATICAS);

  return {
    stats,
    students,
    totalStudents: students.length,
    avgLenguaje: leng.length ? leng.reduce((a, b) => a + b.porcentaje, 0) / leng.length : 0,
    avgMatematicas: math.length ? math.reduce((a, b) => a + b.porcentaje, 0) / math.length : 0,
    detectedColumns: headersEstudiantes.filter(h => h !== null) as string[]
  };
};

export const downloadResultsAsExcel = (results: QuestionStats[]) => {
  const data = results.map(s => ({
    'Ítem/Orden': s.orden,
    'Número de Pregunta': s.pregunta,
    'Cantidad de Aciertos': s.aciertos,
    'Clave Correcta': s.respuestaCorrecta,
    'Total Estudiantes': s.total,
    '% de Logro': `${s.porcentaje.toFixed(1)}%`,
    'Área': s.materia
  }));

  const ws = XLSX.utils.json_to_sheet(data);
  const wb = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb, ws, "Auditoria");
  XLSX.writeFile(wb, "Reporte_Auditoria_Aciertos.xlsx");
};

