import * as XLSX from 'xlsx';
import { Subject, QuestionStats, OptionBreakdown, StudentAnswerDetail, ProcessedResults } from '../types';

const normalizeValue = (val: any): string | null => {
  if (val === null || val === undefined) return null;
  let str = String(val).trim().toUpperCase();
  if (str.endsWith('.0')) {
    str = str.substring(0, str.length - 2);
  }
  if (str === '' || str === 'NR' || str === 'N/R' || str === 'N.R' || str === 'NULL') {
    return null;
  }
  return str;
};

export const parseExcelFile = async (file: File): Promise<any[][]> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = new Uint8Array(e.target?.result as ArrayBuffer);
        const workbook = XLSX.read(data, { type: 'array', cellStyles: true, cellFormula: true, cellLinks: true });
        const worksheet = workbook.Sheets[workbook.SheetNames[0]];
        const rawData: any[][] = XLSX.utils.sheet_to_json(worksheet, { 
          header: 1, 
          defval: "",
          blankrows: false
        });

        // Adjuntamos la hoja de cálculo original para poder extraer links después si es necesario
        // Pero mejor procesamos los links aquí mismo inyectándolos en la matriz
        const range = XLSX.utils.decode_range(worksheet['!ref'] || 'A1');
        for (let r = range.s.r; r <= range.e.r; r++) {
          for (let c = range.s.c; c <= range.e.c; c++) {
            const cellAddress = XLSX.utils.encode_cell({ r, c });
            const cell = worksheet[cellAddress];
            if (cell && cell.l && cell.l.Target) {
              // Si la celda tiene un hipervínculo interno de Excel, lo priorizamos
              // Solo lo hacemos si el valor actual no es ya una URL
              const currentVal = String(rawData[r]?.[c] || '').toLowerCase();
              if (!currentVal.startsWith('http')) {
                // Guardamos el link en una propiedad especial si quisiéramos, 
                // pero para simplificar, si es la columna 0, reemplazamos o guardamos
                if (c === 0) {
                   rawData[r][c] = cell.l.Target;
                }
              }
            }
          }
        }

        resolve(rawData);
      } catch (err) {
        reject(err);
      }
    };
    reader.onerror = (err) => reject(err);
    reader.readAsArrayBuffer(file);
  });
};

